/**
 * Pino Logger Utility for Classification Engine
 *
 * Provides structured, high-performance logging with:
 * - Log level filtering via LOG_LEVEL environment variable
 * - JSON and pretty-print output modes
 * - Child loggers with automatic context propagation
 *
 * @example
 * import { logger } from './utils/logger';
 * logger.info({ emailId: 'abc' }, 'Processing email');
 * logger.debug('Detailed trace');
 * logger.warn('Non-critical issue');
 * logger.error({ error }, 'Critical failure');
 */

import pino from 'pino';

/**
 * Pino logger instance with child logger support
 */
export type Logger = pino.Logger;

/**
 * Get log level from environment (default: 'info')
 * Levels: 'trace', 'debug', 'info', 'warn', 'error', 'fatal'
 */
function getLogLevel(): pino.Level {
  const level = process.env.LOG_LEVEL?.toLowerCase();
  const validLevels = ['trace', 'debug', 'info', 'warn', 'error', 'fatal'];
  return validLevels.includes(level || '') ? (level as pino.Level) : 'info';
}

/**
 * Determine if pretty-print mode should be enabled
 * - Explicitly enabled via PRETTY_LOGS=true
 * - Auto-enabled if NODE_ENV=development and no LOG_JSON override
 */
function shouldPrettyPrint(): boolean {
  if (process.env.PRETTY_LOGS === 'true') return true;
  if (process.env.LOG_JSON === 'true') return false;
  return process.env.NODE_ENV === 'development';
}

/**
 * Create the default classification-engine logger instance
 */
function createDefaultLogger(): pino.Logger {
  const level = getLogLevel();
  const prettyPrint = shouldPrettyPrint();

  if (prettyPrint) {
    return pino({
      level,
      transport: {
        target: 'pino-pretty',
        options: {
          colorize: true,
          translateTime: 'SYS:standard',
          ignore: 'pid,hostname',
        },
      },
    });
  }

  // JSON output (production default)
  return pino({ level });
}

/**
 * Default logger instance for classification-engine
 *
 * @example
 * logger.info('High-level operation completed');
 * logger.debug({ stageData }, 'Detailed classification trace');
 * logger.warn('Deprecated config pattern detected');
 * logger.error({ error }, 'Classification failed');
 */
export const logger = createDefaultLogger();

/**
 * Create a child logger with automatic context propagation
 *
 * @param context - Context to add to all child log entries
 * @returns Child logger instance
 *
 * @example
 * const emailLogger = createChildLogger({ emailId: 'abc123' });
 * emailLogger.info('Processing stage'); // Auto-includes emailId
 */
export function createChildLogger(context: Record<string, unknown>): Logger {
  return logger.child(context);
}

