   137→    sourceField: attr.detectionMethod === 'pattern' ? 'emailBodyOrSubject' : undefined,
   138→    derivationLogic:
   139→      attr.detectionMethod === 'derived' || attr.detectionMethod === 'domainLookup'
   140→        ? attr.detectionEvidence
   141→        : undefined,
   142→    confidence: attr.confidence,
   143→    parallelProcessed: true,
