   145→    reason: attr.detectionEvidence,
   146→  }));
   147→
   148→  result.explainabilityTrace.stageTimings['attributeDetection'] = duration;
   149→  result.explainabilityTrace.configurationRefs['attributeDetection'] = 'attributes.detectors';
   150→}
   151→
   152→/**
   153→ * Detect pattern-based attributes using configured detectors
   154→ */
   155→function detectPatternAttributes(email: EmailMessage, config: AttributeDetectionStageConfig): DetectedAttribute[] {
   156→  const detectors = config.attributes?.detectors || [];
   157→  const detectedAttributes: DetectedAttribute[] = [];
   158→
   159→  for (const detector of detectors) {
   160→    try {
   161→      const detection = applyDetector(email, detector);
   162→      if (detection.detected) {
   163→        detectedAttributes.push({
   164→          attributeName: detector.attribute,
   165→          attributeValue: detection.value as string | number | boolean,
   166→          detectionMethod: 'pattern',
   167→          detectionEvidence: detection.evidence || 'Pattern match',
   168→          confidence: 0.8, // Default confidence for pattern matches
   169→        });
   170→      }
   171→    } catch (error) {
   172→      // Log error but continue processing
   173→      console.warn(`Error applying detector for ${detector.attribute}:`, error);
   174→    }
   175→  }
   176→
   177→  return detectedAttributes;
   178→}
   179→
   180→/**
   181→ * Apply individual detector pattern to email content
   182→ */
   183→function applyDetector(
   184→  email: EmailMessage,
   185→  detector: AttributeDetector
   186→): { detected: boolean; value?: unknown; evidence?: string } {
   187→  const { field, operation, values } = detector;
   188→
   189→  // Get the field content to search
   190→  let searchContent = '';
   191→  switch (field) {
   192→    case 'body':
   193→      searchContent = extractEmailBodyText(email);
   194→      break;
   195→    case 'subject':
   196→      searchContent = email.subject || '';
   197→      break;
   198→    case 'from.address':
   199→      searchContent = email.from?.email || '';
   200→      break;
   201→    case 'from.name':
   202→      searchContent = email.from?.name || '';
   203→      break;
   204→    default:
   205→      console.warn(`Unknown field type for detector: ${field}`);
   206→      return { detected: false };
   207→  }
   208→
   209→  // Apply detection operation
   210→  switch (operation) {
   211→    case 'containsAny':
   212→      for (const value of values) {
   213→        if (searchContent.toLowerCase().includes(value.toLowerCase())) {
   214→          return {
   215→            detected: true,
   216→            value: true,
   217→            evidence: `Found "${value}" in ${field}`,
   218→          };
   219→        }
   220→      }
   221→      break;
   222→
   223→    case 'regexAny':
   224→      for (const pattern of values) {
   225→        try {
   226→          const regex = new RegExp(pattern, 'ig'); // Add global flag for better matching
   227→          const match = searchContent.match(regex);
   228→          if (match) {
   229→            // For amount patterns, try to match the longest currency pattern
   230→            let bestMatch = match[0];
   231→            if (pattern.includes('\\$\\d+')) {
   232→              // Special handling for currency amounts - match full amounts with decimals
   233→              const fullAmountRegex = /\$\d+(?:\.\d{2})?/g;
   234→              const fullMatches = searchContent.match(fullAmountRegex);
   235→              if (fullMatches && fullMatches.length > 0) {
   236→                bestMatch = fullMatches[0]; // Use the first full amount match
   237→              }
   238→            }
   239→            return {
   240→              detected: true,
   241→              value: true,
   242→              evidence: `Regex "${pattern}" matched: "${bestMatch}" in ${field}`,
   243→            };
   244→          }
   245→        } catch (error) {
   246→          console.warn(`Invalid regex pattern: ${pattern}`, error);
   247→          continue;
   248→        }
   249→      }
   250→      break;
   251→
   252→    case 'startsWith':
   253→      for (const value of values) {
   254→        if (searchContent.toLowerCase().startsWith(value.toLowerCase())) {
   255→          return {
   256→            detected: true,
   257→            value: true,
   258→            evidence: `${field} starts with "${value}"`,
   259→          };
   260→        }
   261→      }
   262→      break;
   263→
   264→    case 'endsWith':
   265→      for (const value of values) {
   266→        if (searchContent.toLowerCase().endsWith(value.toLowerCase())) {
   267→          return {
   268→            detected: true,
   269→            value: true,
   270→            evidence: `${field} ends with "${value}"`,
   271→          };
   272→        }
   273→      }
   274→      break;
   275→
   276→    default:
   277→      console.warn(`Unknown operation type: ${operation}`);
   278→  }
   279→
   280→  return { detected: false };
   281→}
   282→
   283→/**
   284→ * Detect derived attributes using logical rules
   285→ */
   286→function detectDerivedAttributes(email: EmailMessage, config: AttributeDetectionStageConfig): DetectedAttribute[] {
   287→  const settings = config.settings?.attributeProcessing;
   288→  const detectedAttributes: DetectedAttribute[] = [];
   289→
   290→  // Derive selfSent attribute (if enabled, default true)
   291→  const detectSelfSent = !settings || settings.detectSelfSent !== false;
   292→  if (detectSelfSent) {
   293→    const selfSent = deriveSelfSent(email);
   294→    if (selfSent) {
   295→      detectedAttributes.push(selfSent);
   296→    }
   297→  }
   298→
   299→  // Domain-based derivations (if enabled, default true)
   300→  const resolveDomains = !settings || settings.resolveDomains !== false;
   301→  if (resolveDomains) {
   302→    // Derive fromFinancialInstitution attribute
   303→    const financialInstitution = deriveFromFinancialInstitution(email, config);
   304→    if (financialInstitution) {
   305→      detectedAttributes.push(financialInstitution);
   306→    }
   307→
   308→    // Derive fromNewsletterSource attribute
   309→    const newsletterSource = deriveFromNewsletterSource(email, config);
   310→    if (newsletterSource) {
   311→      detectedAttributes.push(newsletterSource);
   312→    }
   313→
   314→    // Derive fromLogisticsCarrier attribute
   315→    const logisticsCarrier = deriveFromLogisticsCarrier(email, config);
   316→    if (logisticsCarrier) {
   317→      detectedAttributes.push(logisticsCarrier);
   318→    }
   319→  }
   320→
   321→  // Gmail category derivations (always enabled - based on Gmail API labelIds)
   322→  const gmailCategories = deriveGmailCategories(email);
   323→  detectedAttributes.push(...gmailCategories);
   324→
   325→  return detectedAttributes;
   326→}
   327→
   328→/**
   329→ * Derive selfSent attribute - email sent from user to self
   330→ */
   331→function deriveSelfSent(email: EmailMessage): DetectedAttribute | null {
   332→  const userAddresses = getUserAddresses();
   333→  const fromAddress = email.from?.email?.toLowerCase();
   334→
   335→  // Check if from address is user address
   336→  if (!fromAddress || !userAddresses.includes(fromAddress)) {
   337→    return null;
   338→  }
   339→
   340→  // Check if all recipients are user addresses
   341→  const allRecipients: string[] = [];
   342→  if (email.to) {
   343→    allRecipients.push(...email.to.map((addr) => addr.email.toLowerCase()));
   344→  }
   345→  if (email.cc) {
   346→    allRecipients.push(...email.cc.map((addr) => addr.email.toLowerCase()));
   347→  }
   348→  if (email.bcc) {
   349→    allRecipients.push(...email.bcc.map((addr) => addr.email.toLowerCase()));
   350→  }
   351→
   352→  const allRecipientsAreUser = allRecipients.length > 0 && allRecipients.every((addr) => userAddresses.includes(addr));
   353→
   354→  // Check for List-Id header (exclude mailing lists)
   355→  const hasListId = email.payload?.headers?.some((header) => header.name.toLowerCase() === 'list-id');
   356→
   357→  if (allRecipientsAreUser && !hasListId) {
   358→    return {
   359→      attributeName: 'selfSent',
   360→      attributeValue: true,
   361→      detectionMethod: 'derived',
   362→      detectionEvidence: 'All recipients match user addresses',
   363→      confidence: 0.9,
   364→    };
   365→  }
   366→
   367→  return null;
   368→}
   369→
   370→/**
   371→ * Derive fromFinancialInstitution attribute using domain lookup
   372→ */
   373→function deriveFromFinancialInstitution(
   374→  email: EmailMessage,
   375→  config: AttributeDetectionStageConfig
   376→): DetectedAttribute | null {
   377→  const fromAddress = email.from?.email?.toLowerCase();
   378→  if (!fromAddress) return null;
   379→
   380→  const fromDomain = extractBaseDomain(fromAddress);
   381→  const financialDomains = getFinancialDomains(config);
   382→
   383→  if (financialDomains.includes(fromDomain)) {
   384→    return {
   385→      attributeName: 'fromFinancialInstitution',
   386→      attributeValue: true,
   387→      detectionMethod: 'domainLookup',
   388→      detectionEvidence: fromDomain,
   389→      confidence: 0.85,
   390→    };
   391→  }
   392→
   393→  return null;
   394→}
   395→
   396→/**
   397→ * Derive fromNewsletterSource attribute
   398→ */
   399→function deriveFromNewsletterSource(
   400→  email: EmailMessage,
   401→  config: AttributeDetectionStageConfig
   402→): DetectedAttribute | null {
   403→  const fromAddress = email.from?.email?.toLowerCase();
   404→  if (!fromAddress) return null;
   405→
   406→  const fromDomain = extractBaseDomain(fromAddress);
   407→  const newsletterDomains = getNewsletterDomains(config);
   408→
   409→  // Check domain match
   410→  if (newsletterDomains.includes(fromDomain)) {
   411→    return {
   412→      attributeName: 'fromNewsletterSource',
   413→      attributeValue: true,
   414→      detectionMethod: 'domainLookup',
   415→      detectionEvidence: fromDomain,
   416→      confidence: 0.8,
   417→    };
   418→  }
   419→
   420→  // Check List-Id header presence
   421→  const hasListId = email.payload?.headers?.some((header) => header.name.toLowerCase() === 'list-id');
   422→  if (hasListId) {
   423→    return {
   424→      attributeName: 'fromNewsletterSource',
   425→      attributeValue: true,
   426→      detectionMethod: 'derived',
   427→      detectionEvidence: 'List-Id header present',
   428→      confidence: 0.85,
   429→    };
   430→  }
   431→
   432→  return null;
   433→}
   434→
   435→/**
   436→ * Derive fromLogisticsCarrier attribute
   437→ */
   438→function deriveFromLogisticsCarrier(
   439→  email: EmailMessage,
   440→  config: AttributeDetectionStageConfig
   441→): DetectedAttribute | null {
   442→  const fromAddress = email.from?.email?.toLowerCase();
   443→  if (!fromAddress) return null;
   444→
   445→  const fromDomain = extractBaseDomain(fromAddress);
   446→  const logisticsDomains = getLogisticsDomains(config);
   447→
   448→  if (logisticsDomains.includes(fromDomain)) {
   449→    return {
   450→      attributeName: 'fromLogisticsCarrier',
   451→      attributeValue: true,
   452→      detectionMethod: 'domainLookup',
   453→      detectionEvidence: fromDomain,
   454→      confidence: 0.85,
   455→    };
   456→  }
   457→
   458→  return null;
   459→}
   460→
   461→/**
   462→ * Extract base domain from email address
   463→ */
   464→function extractBaseDomain(email: string): string {
   465→  const domainPart = email.split('@')[1];
   466→  if (!domainPart) return '';
   467→
   468→  // Handle subdomains - return main domain for common patterns
   469→  const parts = domainPart.split('.');
   470→  if (parts.length >= 2) {
   471→    return parts.slice(-2).join('.');
   472→  }
   473→  return domainPart;
   474→}
   475→
   476→/**
   477→ * Get user email addresses for selfSent detection
   478→ */
   479→function getUserAddresses(): string[] {
   480→  // In real implementation, this would come from user configuration
   481→  return ['user@gmail.com', 'scotthamilton77@gmail.com'];
   482→}
   483→
   484→/**
   485→ * Get financial domains for institution detection
   486→ */
   487→function getFinancialDomains(config: AttributeDetectionStageConfig): string[] {
   488→  return config.performanceCache?.financialDomains || [];
   489→}
   490→
   491→/**
   492→ * Get newsletter domains for source detection
   493→ */
   494→function getNewsletterDomains(config: AttributeDetectionStageConfig): string[] {
   495→  return config.performanceCache?.newsletterDomains || [];
   496→}
   497→
   498→/**
   499→ * Get logistics domains for carrier detection
   500→ */
   501→function getLogisticsDomains(config: AttributeDetectionStageConfig): string[] {
   502→  return config.performanceCache?.logisticsDomains || [];
   503→}
   504→
   505→/**
   506→ * Derive Gmail category attributes from Gmail API labelIds
   507→ *
   508→ * Gmail automatically categorizes emails into Social, Promotions, and Updates.
   509→ * These categories are exposed via Gmail API as labelIds: CATEGORY_SOCIAL,
   510→ * CATEGORY_PROMOTIONS, CATEGORY_UPDATES.
   511→ *
   512→ * We use these as PRIMARY_BOOST signals to boost relevant categories:
   513→ * - CATEGORY_SOCIAL → boosts personal category
   514→ * - CATEGORY_PROMOTIONS → boosts marketingPromotions category
   515→ * - CATEGORY_UPDATES → boosts subscriptionContent/systemNotifications categories
   516→ *
   517→ * TODO this should be configuration-driven
   518→ */
   519→function deriveGmailCategories(email: EmailMessage): DetectedAttribute[] {
   520→  const gmailLabels = email.gmailLabels || [];
   521→  const detectedAttributes: DetectedAttribute[] = [];
   522→
   523→  // Check for Social category
   524→  if (gmailLabels.includes('CATEGORY_SOCIAL')) {
   525→    detectedAttributes.push({
   526→      attributeName: 'gmailCategorySocial',
   527→      attributeValue: true,
   528→      detectionMethod: 'derived',
   529→      detectionEvidence: 'Gmail labeled as CATEGORY_SOCIAL',
   530→      confidence: 0.9, // High confidence - Gmail's ML is sophisticated
   531→    });
   532→  }
   533→
   534→  // Check for Promotions category
   535→  if (gmailLabels.includes('CATEGORY_PROMOTIONS')) {
   536→    detectedAttributes.push({
   537→      attributeName: 'gmailCategoryPromotions',
   538→      attributeValue: true,
   539→      detectionMethod: 'derived',
   540→      detectionEvidence: 'Gmail labeled as CATEGORY_PROMOTIONS',
   541→      confidence: 0.9,
   542→    });
   543→  }
   544→
   545→  // Check for Updates category
   546→  if (gmailLabels.includes('CATEGORY_UPDATES')) {
   547→    detectedAttributes.push({
   548→      attributeName: 'gmailCategoryUpdates',
   549→      attributeValue: true,
   550→      detectionMethod: 'derived',
   551→      detectionEvidence: 'Gmail labeled as CATEGORY_UPDATES',
   552→      confidence: 0.9,
   553→    });
   554→  }
   555→
   556→  return detectedAttributes;
   557→}
   558→
   559→/**
   560→ * Detect urgency level from email content and headers
   561→ *
   562→ * Analyzes subject, body, and X-Priority header to determine urgency level.
   563→ * Returns one of: 'none', 'low', 'medium', 'high' (matching config schema)
   564→ *
   565→ * TODO: Make this configuration-driven rather than hardcoded
   566→ * Suggested approach: Add urgency detectors to config.processingConfig.attributes.detectors
   567→ * with tier-based patterns similar to rule-based classification:
   568→ * {
   569→ *   "attribute": "urgency",
   570→ *   "tiers": {
   571→ *     "high": { patterns: [...], headerConditions: { "X-Priority": [1, 2] } },
   572→ *     "medium": { patterns: [...], headerConditions: { "X-Priority": [3] } },
   573→ *     "low": { patterns: [...] },
   574→ *     "none": { isDefault: true }
   575→ *   }
   576→ * }
   577→ *
   578→ * Current hardcoded patterns:
   579→ *
   580→ * High urgency indicators:
   581→ * - Keywords: "urgent", "immediately", "asap", "critical", "emergency", "overdue", "action required"
   582→ * - X-Priority header: 1 or 2
   583→ *
   584→ * Medium urgency indicators:
   585→ * - Keywords: "soon", "important", "please review", "time sensitive"
   586→ * - X-Priority header: 3
   587→ *
   588→ * Low urgency indicators:
   589→ * - Keywords: "fyi", "no rush", "when you have time", "at your convenience"
   590→ * - X-Priority header: 4 or 5
   591→ *
   592→ * None urgency: No urgency indicators detected (current default)
   593→ */
   594→function detectUrgency(email: EmailMessage): 'none' | 'low' | 'medium' | 'high' {
   595→  const subject = (email.subject || '').toLowerCase();
   596→  const body = extractEmailBodyText(email).toLowerCase();
   597→  const contentText = `${subject} ${body}`;
   598→
   599→  // Check X-Priority header (1 = highest, 5 = lowest)
   600→  const xPriority = email.payload?.headers?.find((h) => h.name.toLowerCase() === 'x-priority')?.value;
   601→  const priorityNum = xPriority ? parseInt(xPriority, 10) : null;
   602→
   603→  // High urgency patterns
   604→  const highUrgencyKeywords = [
   605→    'urgent',
   606→    'immediately',
   607→    'asap',
   608→    'critical',
   609→    'emergency',
   610→    'overdue',
   611→    'action required',
   612→    'respond immediately',
   613→    'time-sensitive',
   614→  ];
   615→
   616→  // Medium urgency patterns
   617→  const mediumUrgencyKeywords = [
   618→    'soon',
   619→    'important',
   620→    'please review',
   621→    'time sensitive',
   622→    'attention needed',
   623→    'follow up',
   624→  ];
   625→
   626→  // Low urgency patterns
   627→  const lowUrgencyKeywords = ['fyi', 'for your information', 'no rush', 'when you have time', 'at your convenience'];
   628→
   629→  // Check for high urgency
   630→  if (priorityNum !== null && priorityNum <= 2) {
   631→    return 'high';
   632→  }
   633→
   634→  for (const keyword of highUrgencyKeywords) {
   635→    if (contentText.includes(keyword)) {
   636→      return 'high';
   637→    }
   638→  }
   639→
   640→  // Check for medium urgency
   641→  if (priorityNum === 3) {
   642→    return 'medium';
   643→  }
   644→
   645→  for (const keyword of mediumUrgencyKeywords) {
   646→    if (contentText.includes(keyword)) {
   647→      return 'medium';
   648→    }
   649→  }
   650→
   651→  // Check for explicit low urgency (X-Priority 4 or 5)
   652→  if (priorityNum !== null && priorityNum >= 4) {
   653→    return 'low';
   654→  }
   655→
   656→  // Check for low urgency keywords
   657→  for (const keyword of lowUrgencyKeywords) {
   658→    if (contentText.includes(keyword)) {
   659→      return 'low';
   660→    }
   661→  }
   662→
   663→  // Default to 'none' (no urgency indicators detected)
   664→  // This matches config schema which includes "none" as a valid value
   665→  return 'none';
   666→}
