   160→                schema: config.featureExtractionSchema.schema,
   161→                strict: config.featureExtractionSchema.strict ?? true,
   162→              },
   163→            }
   164→          : { type: 'json_object' as const }; // Backward compatibility
   165→
   166→      // Call OpenAI API with structured outputs
   167→      const response = await openai.chat.completions.create({
   168→        model: config.openai.model,
   169→        temperature: config.openai.temperature,
   170→        response_format: responseFormat,
   171→        messages: [
   172→          { role: 'system', content: systemPrompt },
   173→          { role: 'user', content: userPrompt },
   174→        ],
   175→      });
   176→
   177→      // Parse and validate response
   178→      const rawContent = response.choices[0].message.content;
   179→      if (!rawContent) {
   180→        throw new Error('Empty response from OpenAI');
   181→      }
   182→
   183→      let featureExtractionData: FeatureExtractionData;
   184→      try {
   185→        featureExtractionData = JSON.parse(rawContent);
   186→      } catch {
   187→        throw new Error('Invalid JSON response from OpenAI');
   188→      }
   189→
   190→      // Schema validation: For structured outputs, OpenAI enforces the schema.
   191→      // For backward compatibility with json_object mode, we still validate with AJV.
   192→      const validationErrors: string[] = [];
   193→      let validationPassed = true;
   194→
   195→      if (config.openai.responseFormat === 'json_object') {
   196→        // Only validate with AJV for legacy json_object mode
   197→        validationPassed = validateSchema(featureExtractionData);
   198→
   199→        if (!validationPassed && validateSchema.errors) {
   200→          for (const error of validateSchema.errors) {
   201→            validationErrors.push(`${error.instancePath} ${error.message}`);
   202→          }
   203→          throw new Error('Schema validation failed: ' + validationErrors.join(', '));
   204→        }
