   309→    if (!scoreData || typeof scoreData !== 'object') {
   310→      throw new Error(`Invalid candidate score for category ${category}: must be an object`);
   311→    }
   312→    if (typeof scoreData.score !== 'number') {
   313→      throw new Error(`Invalid candidate score for category ${category}: score must be a number`);
   314→    }
   315→  }
   316→
   317→  if (!config) {
   318→    throw new Error('Configuration is required');
   319→  }
   320→
   321→  if (!config.openai?.apiKey || config.openai.apiKey.trim() === '') {
   322→    throw new Error('Invalid configuration: OpenAI API key is required');
   323→  }
   324→
   325→  if (!config.prompts?.systemPrompt || !config.prompts?.userPrompt) {
   326→    throw new Error('Invalid configuration: system and user prompts are required');
   327→  }
   328→
   329→  if (!config.featureExtractionSchema) {
   330→    throw new Error('Invalid configuration: feature extraction schema is required');
   331→  }
   332→}
