   334→/**
   335→ * Interpolate user prompt template with email content and analysis data
   336→ *
   337→ * Supports dynamic object path resolution with these placeholders:
   338→ * - {email.from} - formatted email address
   339→ * - {email.subject} - email subject
   340→ * - {email.body} - email body text
   341→ * - {candidateCategories} - JSON formatted candidate categories
   342→ * - {detectedAttributes} - JSON formatted detected attributes
   343→ */
   344→function interpolateUserPrompt(
   345→  userPromptTemplate: string[],
   346→  email: EmailMessage,
   347→  candidateCategories: Record<string, CandidateScore>,
   348→  detectedAttributes: AttributeContext
   349→): string {
   350→  const template = userPromptTemplate.join('\n');
   351→
   352→  // Create interpolation context with all available data
   353→  const context = {
   354→    email: {
   355→      from: formatEmailAddress(email.from),
   356→      subject: email.subject || '',
   357→      body: getEmailBodyText(email),
   358→    },
   359→    candidateCategories: formatObjectForTemplate(candidateCategories as unknown as Record<string, unknown>),
   360→    detectedAttributes: formatObjectForTemplate(detectedAttributes as unknown as Record<string, unknown>),
   361→  };
   362→
   363→  // Perform template interpolation using dynamic path resolution
   364→  return interpolateTemplate(template, context);
   365→}
   366→
   367→/**
   368→ * Validate that quoted phrases in evidence actually exist in the email content
   369→ */
   370→function validateEvidenceGrounding(email: EmailMessage, featureExtraction: FeatureExtractionData): EvidenceValidation {
   371→  const emailText = (email.subject + ' ' + getEmailBodyText(email)).toLowerCase();
   372→  const validPhrases: string[] = [];
   373→  const invalidPhrases: string[] = [];
   374→
   375→  // Check all quoted phrases in category enhancements
   376→  for (const [, enhancement] of Object.entries(featureExtraction.categoryEnhancements || {})) {
   377→    if (enhancement.evidence?.quotedPhrases) {
   378→      for (const phrase of enhancement.evidence.quotedPhrases) {
   379→        const normalizedPhrase = phrase.toLowerCase().trim();
   380→        if (normalizedPhrase && emailText.includes(normalizedPhrase)) {
   381→          validPhrases.push(phrase);
   382→        } else if (normalizedPhrase) {
   383→          invalidPhrases.push(phrase);
   384→        }
   385→      }
   386→    }
   387→  }
   388→
   389→  return {
   390→    validPhrases,
   391→    invalidPhrases,
   392→    fabricationDetected: invalidPhrases.length > 0,
   393→  };
   394→}
