   448→  private async createBackup(filepath: string, hash: string): Promise<void> {
   449→    try {
   450→      const backupDir = join(dirname(filepath), '.backups');
   451→      await fs.mkdir(backupDir, { recursive: true });
   452→
   453→      const filename = basename(filepath);
   454→      const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
   455→      const backupPath = join(backupDir, `${filename}.${timestamp}.${hash.slice(0, 8)}.backup`);
   456→
   457→      await fs.copyFile(filepath, backupPath);
   458→
   459→      // Keep only last 10 backups
   460→      const backups = await fs.readdir(backupDir);
   461→      const fileBackups = backups
   462→        .filter((f: string) => f.startsWith(filename))
   463→        .sort()
   464→        .reverse();
   465→
   466→      for (const backup of fileBackups.slice(10)) {
