   474→  private async compileConfigurationRules(config: CategoryConfiguration): Promise<CompiledRule[]> {
   475→    const startTime = Date.now();
   476→    const compiledRules: CompiledRule[] = [];
   477→
   478→    for (const [categoryName, category] of Object.entries(config.processingConfig.topLevelCategories)) {
   479→      for (const [subtypeName, subtype] of Object.entries(category.subtypes)) {
   480→        if (subtype.ruleBasedClassification) {
   481→          for (const [tier, rules] of Object.entries(subtype.ruleBasedClassification)) {
   482→            if (rules) {
   483→              for (const rule of rules) {
   484→                try {
   485→                  let pattern: RegExp;
   486→
   487→                  switch (rule.operation) {
   488→                    case 'containsAny':
   489→                      pattern = new RegExp(
   490→                        rule.values?.map((v) => v.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).join('|') || '',
   491→                        'i'
   492→                      );
   493→                      break;
   494→                    case 'startsWith':
   495→                      pattern = new RegExp(
   496→                        '^(' +
   497→                          (rule.values?.map((v) => v.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).join('|') || '') +
   498→                          ')',
   499→                        'i'
   500→                      );
   501→                      break;
   502→                    case 'endsWith':
   503→                      pattern = new RegExp(
   504→                        '(' +
   505→                          (rule.values?.map((v) => v.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).join('|') || '') +
   506→                          ')$',
   507→                        'i'
   508→                      );
   509→                      break;
   510→                    case 'regexAny':
   511→                      pattern = new RegExp(rule.values?.join('|') || '', 'i');
   512→                      break;
   513→                    default:
   514→                      continue; // Skip unknown operations
   515→                  }
   516→
   517→                  compiledRules.push({
   518→                    category: categoryName,
   519→                    subtype: subtypeName,
   520→                    tier: tier as 'high' | 'medium' | 'low',
   521→                    pattern,
   522→                    weight: rule.weight,
   523→                    parallelSafe: true, // Assume parallel safe unless marked otherwise
   524→                  });
   525→                } catch (error) {
   526→                  console.warn(`Failed to compile rule for ${categoryName}.${subtypeName}.${tier}:`, error);
   527→                }
   528→              }
   529→            }
   530→          }
   531→        }
   532→      }
   533→    }
   534→
   535→    // Update performance metrics
   536→    if (!config.performanceMetrics) {
   537→      config.performanceMetrics = {};
   538→    }
   539→    config.performanceMetrics.ruleCompilationTimeMs = Date.now() - startTime;
   540→    config.performanceMetrics.totalRules = compiledRules.length;
   541→    config.performanceMetrics.parallelCompatibleRules = compiledRules.filter((r) => r.parallelSafe).length;
   542→
   543→    return compiledRules;
   544→  }
