   546→  private async computeAttributeMatrix(config: CategoryConfiguration): Promise<AttributeInfluenceMatrix> {
   547→    const startTime = Date.now();
   548→    const matrix: AttributeInfluenceMatrix = {};
   549→
   550→    // Build attribute influence matrix from attributeRelevance configuration
   551→    const attributeRelevance = config.processingConfig.attributeRelevance;
   552→
   553→    for (const [categoryName, categoryConfig] of Object.entries(attributeRelevance)) {
   554→      if (categoryName === '_roles_legend') continue;
   555→
   556→      // Type guard to ensure we have the correct structure
   557→      if (typeof categoryConfig === 'object' && categoryConfig !== null && 'categoryRoles' in categoryConfig) {
   558→        matrix[categoryName] = {};
   559→
   560→        // Process category-level roles
   561→        if (categoryConfig.categoryRoles) {
   562→          for (const [attributeName, role] of Object.entries(categoryConfig.categoryRoles)) {
   563→            matrix[categoryName][attributeName] = {
   564→              role: role as AttributeRole,
   565→              bonus: this.getRoleBonus(role as string),
   566→              cap: this.getRoleCap(role as string),
   567→            };
   568→          }
   569→        }
   570→
   571→        // Process subtype-specific roles
   572→        if (categoryConfig.subtypes) {
   573→          for (const [subtypeName, subtypeConfig] of Object.entries(categoryConfig.subtypes)) {
   574→            const subtypeKey = `${categoryName}.${subtypeName}`;
   575→            matrix[subtypeKey] = {};
   576→
   577→            for (const [attributeName, role] of Object.entries(subtypeConfig.roles)) {
   578→              matrix[subtypeKey][attributeName] = {
   579→                role: role as AttributeRole,
   580→                bonus: this.getRoleBonus(role as string),
   581→                cap: this.getRoleCap(role as string),
   582→              };
   583→            }
   584→          }
   585→        }
   586→      }
   587→    }
   588→
   589→    // Update performance metrics
   590→    if (!config.performanceMetrics) {
   591→      config.performanceMetrics = {};
   592→    }
   593→    config.performanceMetrics.matrixComputationTimeMs = Date.now() - startTime;
   594→
   595→    return matrix;
   596→  }
