   598→  private getRoleBonus(role: string): number {
   599→    switch (role) {
   600→      case 'CORE':
   601→        return 0.4;
   602→      case 'PRIMARY_BOOST':
   603→        return 0.3;
   604→      case 'SECONDARY_BOOST':
   605→        return 0.2;
   606→      case 'DISAMBIGUATOR':
   607→        return 0.15;
   608→      case 'FILTER':
   609→        return -0.1;
   610→      default:
   611→        return 0;
   612→    }
   613→  }
   614→
   615→  private getRoleCap(role: string): number {
   616→    switch (role) {
   617→      case 'CORE':
   618→        return 0.5;
   619→      case 'PRIMARY_BOOST':
   620→        return 0.4;
   621→      case 'SECONDARY_BOOST':
   622→        return 0.3;
