   785→    crossReferencesChecked: number
   786→  ): ValidationResult {
   787→    const criticalIssues = errors.filter((e) => e.severity === 'error').length;
   788→    const totalErrors = errors.length;
   789→    const totalWarnings = warnings.length;
   790→
   791→    let configurationHealth: 'excellent' | 'good' | 'fair' | 'poor';
   792→    if (criticalIssues === 0 && totalWarnings === 0) {
   793→      configurationHealth = 'excellent';
   794→    } else if (criticalIssues === 0 && totalWarnings <= 3) {
   795→      configurationHealth = 'good';
   796→    } else if (criticalIssues <= 2 && totalWarnings <= 10) {
   797→      configurationHealth = 'fair';
   798→    } else {
   799→      configurationHealth = 'poor';
   800→    }
   801→
   802→    const recommendedActions: string[] = [];
   803→    if (criticalIssues > 0) {
   804→      recommendedActions.push(`Fix ${criticalIssues} critical error(s)`);
   805→    }
   806→    if (totalWarnings > 5) {
   807→      recommendedActions.push('Review and address configuration warnings');
   808→    }
   809→    if (configurationHealth === 'poor') {
   810→      recommendedActions.push('Consider restructuring configuration for better maintainability');
   811→    }
   812→
   813→    return {
   814→      isValid: criticalIssues === 0,
   815→      errors,
   816→      warnings,
   817→      performance: {
