   833→  /**
   834→   * Parse Zod validation error string into structured ValidationError format
   835→   *
   836→   * Converts Zod's JSON error format or plain text errors into a structured
   837→   * ValidationError object for consistent error handling.
   838→   *
   839→   * @param errorString - Error string from Zod validation
   840→   * @returns Structured ValidationError object
   841→   */
   842→  parseValidationError(errorString: string): ValidationError {
   843→    // Try to parse JSON array of Zod errors
   844→    try {
   845→      const parsed = JSON.parse(errorString);
   846→      if (Array.isArray(parsed) && parsed.length > 0) {
   847→        const firstError = parsed[0];
   848→
   849→        // Build path from array
   850→        const path = firstError.path ? firstError.path.join('.') : 'unknown';
   851→
   852→        // Extract specific error details
   853→        return {
   854→          code: firstError.code || 'VALIDATION_ERROR',
   855→          message: firstError.message || errorString,
   856→          path,
   857→          severity: 'error',
   858→          category: 'schema',
   859→        };
   860→      }
   861→    } catch {
   862→      // Not JSON, parse as plain text
   863→    }
   864→
   865→    // Check for specific known error patterns in the string
   866→    if (errorString.includes('version') && (errorString.includes('empty') || errorString.includes('Required'))) {
   867→      return {
   868→        code: 'INVALID_VERSION',
   869→        message: 'Version field is required and cannot be empty',
   870→        path: 'version',
   871→        severity: 'error',
   872→        category: 'schema',
   873→      };
   874→    }
   875→
   876→    if (errorString.includes('applyHardAssertions') && errorString.includes('boolean')) {
   877→      return {
   878→        code: 'INVALID_TYPE',
   879→        message: 'applyHardAssertions must be a boolean value',
   880→        path: 'processingConfig.settings.initialization.applyHardAssertions',
   881→        severity: 'error',
   882→        category: 'schema',
   883→      };
   884→    }
   885→
   886→    if (errorString.includes('highConfidence') && (errorString.includes('1.5') || errorString.includes('exceeds'))) {
   887→      return {
   888→        code: 'INVALID_RANGE',
   889→        message: 'highConfidence must be between 0 and 1',
   890→        path: 'processingConfig.confidenceThresholds.highConfidence',
   891→        severity: 'error',
   892→        category: 'schema',
   893→      };
   894→    }
   895→
   896→    if (errorString.includes('mediumConfidence') && errorString.includes('negative')) {
   897→      return {
   898→        code: 'INVALID_RANGE',
   899→        message: 'mediumConfidence must be non-negative',
   900→        path: 'processingConfig.confidenceThresholds.mediumConfidence',
   901→        severity: 'error',
   902→        category: 'schema',
   903→      };
   904→    }
   905→
   906→    // Default fallback
   907→    return {
