   916→  /**
   917→   * Detect rule conflicts (duplicate patterns in different categories)
   918→   *
   919→   * Checks for hard assertion patterns that appear in multiple categories,
   920→   * which would cause ambiguous classification results.
   921→   *
   922→   * @param config - Category configuration to check
   923→   * @returns Array of validation errors for detected conflicts
   924→   */
   925→  detectRuleConflicts(config: CategoryConfiguration): ValidationError[] {
   926→    const errors: ValidationError[] = [];
   927→    const subjectPrefixMap = new Map<string, string[]>();
   928→    const fromAddressMap = new Map<string, string[]>();
   929→
   930→    // Skip if categorySignals is not defined
   931→    if (!config.processingConfig?.categorySignals) {
