   934→
   935→    // Collect all hard assertion patterns
   936→    for (const [categoryName, signals] of Object.entries(config.processingConfig.categorySignals)) {
   937→      // Check subject prefixes
   938→      if (signals.hardAssertions?.subjectPrefixes) {
   939→        for (const prefix of signals.hardAssertions.subjectPrefixes) {
   940→          const existing = subjectPrefixMap.get(prefix) || [];
   941→          existing.push(categoryName);
   942→          subjectPrefixMap.set(prefix, existing);
   943→        }
   944→      }
   945→
   946→      // Check from addresses
   947→      if (signals.hardAssertions?.fromAddresses) {
   948→        for (const address of signals.hardAssertions.fromAddresses) {
   949→          const existing = fromAddressMap.get(address) || [];
   950→          existing.push(categoryName);
   951→          fromAddressMap.set(address, existing);
   952→        }
   953→      }
   954→    }
   955→
   956→    // Report duplicate subject prefixes
   957→    for (const [pattern, categories] of Array.from(subjectPrefixMap.entries())) {
   958→      if (categories.length > 1) {
   959→        errors.push({
