   974→          code: 'RULE_CONFLICT',
   975→          message: `duplicate hard assertion address "${address}" found in categories: ${categories.join(', ')}`,
   976→          path: `categorySignals.hardAssertions.fromAddresses`,
   977→          severity: 'error',
   978→          category: 'logic',
   979→          suggestion: 'Remove duplicate address or make it unique to one category',
