/**
 * Format email address for prompt display
 *
 * Handles various input formats and returns a consistent display format.
 *
 * @param address - Email address in various formats (string, object, etc.)
 * @returns Formatted email address string
 *
 * @example
 * formatEmailAddress({ name: 'John Doe', email: 'john@example.com' })
 * // Returns: "John Doe <john@example.com>"
 */
export function formatEmailAddress(address: unknown): string {
  if (!address) return 'Unknown';

  if (typeof address === 'string') return address;

  if (typeof address === 'object' && address !== null) {
    const addr = address as Record<string, string>;
    if (addr.name && addr.email) {
      return `${addr.name} <${addr.email}>`;
    }
    return addr.email || addr.raw || 'Unknown';
  }

  return 'Unknown';
}

/**
 * Extract email body text with HTML fallback
 *
 * Prefers plain text body, falls back to HTML with safe stripping of tags,
 * scripts, styles, and entities.
 *
 * @param email - EmailMessage object containing body content
 * @returns Clean text representation of email body
 *
 * @example
 * getEmailBodyText(email)
 * // Returns: "Your monthly statement is now available..."
 */
export function getEmailBodyText(email: EmailMessage): string {
  if (email.bodyPlain) {
    return email.bodyPlain;
  }

  if (email.bodyHtml) {
    // Improved HTML stripping with better performance and safety
    return email.bodyHtml
      .replace(/<script[^>]*>.*?<\/script>/gi, '') // Remove script blocks
      .replace(/<style[^>]*>.*?<\/style>/gi, '') // Remove style blocks
      .replace(/<[^>]*>/g, '') // Remove HTML tags
      .replace(/&[#A-Za-z0-9]+;/g, ' ') // Remove HTML entities
      .replace(/\s+/g, ' ') // Normalize whitespace
      .trim();
  }

  return '[No body content available]';
}

