      sourceConfig = validateDomainSources(rawConfig);
    } catch (validationError) {
      logger.error({ error: validationError }, 'domain-sources schema validation failed');
      logger.warn('Using empty domain lookup due to validation error');
      return {};
    }

    // Transform to domainLookup format
    const domainLookup: DomainLookup = {};

    for (const [categoryName, categoryData] of Object.entries(sourceConfig)) {
      // Skip metadata entry (not a category)
      if (categoryName === 'metadata') {
