   508→  ): Promise<EmailMessage[]> {
   509→    const emails: EmailMessage[] = [];
   510→
   511→    // Process in batches to avoid overwhelming the API
   512→    for (let i = 0; i < messages.length; i += batchSize) {
   513→      const batch = messages.slice(i, i + batchSize);
   514→      const batchPromises = batch.map(async (msg) => {
   515→        // Validate message ID
