/**
 * Gmail Email Fetcher with Pagination
 *
 * Provides robust email fetching capabilities with pagination, batch processing,
 * error recovery, and Gmail API response parsing.
 *
 * ## Page vs Batch Distinction
 *
 * This module uses two levels of chunking for optimal performance:
 *
 * ### Pages (Gmail API Level)
 * - A **page** is a set of message references (IDs) returned by Gmail's `list()` API
 * - Contains only metadata (message ID, thread ID), not full email content
 * - Size controlled by `maxResults` option (default: 100)
 * - Gmail returns `nextPageToken` when more pages are available
 * - Used for **pagination** through large result sets (e.g., 10,000 emails)
 *
 * ### Batches (Implementation Level)
 * - A **batch** is our internal grouping for fetching full message details
 * - After getting a page of IDs, we call `get()` for each to retrieve full content
 * - Instead of fetching all simultaneously, we split into smaller batches
 * - Size controlled by `batchSize` option (default: 10)
 * - Batches are processed **in parallel** using `Promise.all()`
 * - Prevents overwhelming the Gmail API with hundreds of concurrent requests
 *
 * ### Example Flow
 * ```
 * 1. Gmail API list() → Page 1: [msg1...msg100]      (maxResults=100)
 *    ↓
 * 2. Split into batches:
 *    - Batch 1: [msg1...msg10]                       (batchSize=10)
 *    - Batch 2: [msg11...msg20]
 *    - ...
 *    - Batch 10: [msg91...msg100]
 *    ↓
 * 3. Process each batch with Promise.all() for parallel fetching
 *    ↓
 * 4. If nextPageToken exists → fetch Page 2 and repeat
 * ```
 *
 * This two-level approach balances Gmail API limits, network efficiency,
 * and rate limiting while maintaining optimal performance.
 *
 * @packageDocumentation
 */

import { gmail_v1 } from 'googleapis';
import { parseOneAddress, parseAddressList } from 'email-addresses';
import { GmailClient } from './gmail-client';
import {
  EmailMessage,
  EmailHeader,
  EmailAddress,
  MessagePart,
  MessagePartBody,
} from '@gmail-automation/classification-engine';
import { createLogger } from '../logging/logger-factory';

const logger = createLogger();

// Re-export types for convenience
export type { EmailMessage, EmailAddress };

/**
 * Options for fetching emails
 */
export interface FetchEmailsOptions {
  /**
   * Maximum number of emails to fetch per page
   * @default 100
   */
  maxResults?: number;

  /**
   * Gmail search query filter
   */
  query?: string;

  /**
   * Label IDs to filter by
   */
  labelIds?: string[];

  /**
   * Page token for pagination
   */
  pageToken?: string;

  /**
   * Fetch all pages (ignores maxResults for total, but uses it per page)
   * @default false
   */
  fetchAll?: boolean;

  /**
   * Maximum total emails to fetch (safety limit for fetchAll)
   * Prevents memory exhaustion when fetching large mailboxes
   * @default 10000
   */
  maxTotalEmails?: number;

  /**
   * Message format (full, minimal, metadata, raw)
   * @default 'full'
   */
  format?: 'full' | 'minimal' | 'metadata' | 'raw';

  /**
   * Batch size for fetching message details
   * @default 10
   */
  batchSize?: number;

  /**
   * Continue fetching on individual message errors
   * @default true
   */
  continueOnError?: boolean;
}

/**
 * Fetch error details
 */
export interface FetchError {
  /**
   * Message ID that failed
   */
  messageId: string;

  /**
   * Error message
   */
  error: string;

  /**
   * Gmail API error code (if available)
   */
  errorCode?: string | number;

  /**
   * Stack trace for debugging (only in development)
   */
  stackTrace?: string;

  /**
   * Timestamp of error
   */
  timestamp: Date;
}

/**
 * Result of email fetch operation
 */
export interface FetchEmailsResult {
  /**
   * Fetched emails
   */
  emails: EmailMessage[];

  /**
   * Total number of emails fetched
   */
  totalFetched: number;

  /**
   * Whether there are more emails to fetch
   */
  hasMore: boolean;

  /**
   * Next page token (if hasMore is true)
   */
  nextPageToken?: string;

  /**
   * Errors encountered during fetch
   */
  errors: FetchError[];

  /**
   * Fetch operation duration in milliseconds
   */
  durationMs: number;
}

/**
 * Gmail email fetcher with pagination and batch processing
 *
 * Handles pagination, batch fetching of message details, error recovery,
 * and Gmail API response parsing.
 *
 * @example
 * ```typescript
 * const client = new GmailClient(credentials);
 * const fetcher = new EmailFetcher(client);
 *
 * // Fetch first page of unread emails
 * const result = await fetcher.fetchEmails({
 *   query: 'is:unread',
 *   maxResults: 50
 * });
 *
 * // Fetch next page
 * if (result.hasMore) {
 *   const nextPage = await fetcher.fetchEmails({
 *     pageToken: result.nextPageToken
 *   });
 * }
 *
 * // Fetch all emails
 * const allEmails = await fetcher.fetchEmails({
 *   query: 'label:inbox',
 *   fetchAll: true
 * });
 * ```
 */
export class EmailFetcher {
  /**
   * Creates a new email fetcher
   *
   * @param gmailClient - Authenticated Gmail client
   */
  constructor(private readonly gmailClient: GmailClient) {
    // Store full client to leverage retry logic and auth management
  }

  /**
   * Fetch emails with pagination support
   *
   * @param options - Fetch options
   * @returns Fetch result with emails and pagination info
   */
  async fetchEmails(options: FetchEmailsOptions = {}): Promise<FetchEmailsResult> {
    const startTime = Date.now();
    const {
      maxResults = 100,
      query,
      labelIds,
      pageToken,
      fetchAll = false,
      maxTotalEmails = 10000,
      format = 'full',
      batchSize = 10,
      continueOnError = true,
    } = options;

    logger.info(
      {
        maxResults,
        query: query || 'none',
        labelIds: labelIds || 'none',
        fetchAll,
        maxTotalEmails,
        format,
        batchSize,
      },
      'Starting email fetch'
    );

    const allEmails: EmailMessage[] = [];
    const allErrors: FetchError[] = [];
    let currentPageToken: string | undefined = pageToken;
    let hasMore = false;
    let pageCount = 0;
    let hitSafetyLimit = false;

    do {
      pageCount++;

      // Check safety limit before fetching next page
      if (allEmails.length >= maxTotalEmails) {
        logger.warn(
          { maxTotalEmails, currentCount: allEmails.length },
          `Reached maxTotalEmails limit (${maxTotalEmails}), stopping fetch`
        );
        hitSafetyLimit = true;
        hasMore = true; // There may be more, but we're stopping
        break;
      }

      logger.debug({ pageCount, pageToken: currentPageToken || 'none' }, `Fetching page ${pageCount}`);

      // Fetch message list using GmailClient (with built-in retry logic)
      const listParams: gmail_v1.Params$Resource$Users$Messages$List = {
        maxResults,
      };

      if (query) {
        listParams.q = query;
      }

      if (labelIds && labelIds.length > 0) {
        listParams.labelIds = labelIds;
      }

      if (currentPageToken) {
        listParams.pageToken = currentPageToken;
      }

      const listResponse = await this.gmailClient.listMessages(listParams, {
        retryOnRateLimit: true,
        maxRetries: 3,
      });
      const messages = listResponse.messages || [];

      logger.info({ pageCount, messageCount: messages.length }, `Page ${pageCount}: Found ${messages.length} messages`);

      // Fetch message details in batches
      const emails = await this.fetchMessageDetails(messages, format, batchSize, continueOnError, allErrors);
      allEmails.push(...emails);

      logger.debug(
        { pageCount, emailCount: emails.length },
        `Page ${pageCount}: Successfully fetched ${emails.length} emails`
      );

      // Check for more pages
      currentPageToken = listResponse.nextPageToken || undefined;
      hasMore = !!currentPageToken;
    } while (fetchAll && hasMore);

    const durationMs = Date.now() - startTime;

    logger.info(
      {
        totalFetched: allEmails.length,
        errors: allErrors.length,
        durationMs,
        hasMore: !fetchAll && hasMore,
        pagesProcessed: pageCount,
      },
      'Email fetch completed'
    );

    return {
      emails: allEmails,
      totalFetched: allEmails.length,
      hasMore: hitSafetyLimit ? true : !fetchAll && hasMore,
      nextPageToken: !fetchAll ? currentPageToken : undefined,
      errors: allErrors,
      durationMs,
    };
  }

  /**
   * Fetch emails since a specific date
   *
   * Convenience method that constructs a Gmail query to fetch emails
   * received after the specified date.
   *
   * @param sinceDate - Fetch emails received after this date
   * @param options - Additional fetch options
   * @returns Fetch result with emails
   */
  async fetchEmailsSince(sinceDate: Date, options: FetchEmailsOptions = {}): Promise<EmailMessage[]> {
    // Gmail query format: after:YYYY/MM/DD
    const year = sinceDate.getFullYear();
    const month = String(sinceDate.getMonth() + 1).padStart(2, '0');
    const day = String(sinceDate.getDate()).padStart(2, '0');
    const dateQuery = `after:${year}/${month}/${day}`;

    // Combine with any existing query
    const query = options.query ? `${dateQuery} ${options.query}` : dateQuery;

    // Fetch all emails matching the query
    const result = await this.fetchEmails({
      ...options,
      query,
      fetchAll: true, // Fetch all emails since date
    });

    return result.emails;
  }

  /**
   * Fetch single email by ID
   *
   * @param messageId - Gmail message ID
   * @param format - Message format
   * @returns Email message
   */
  async fetchEmailById(
    messageId: string,
    format: 'full' | 'minimal' | 'metadata' | 'raw' = 'full'
  ): Promise<EmailMessage> {
    const message = await this.gmailClient.getMessage(messageId, format, {
      retryOnRateLimit: true,
      maxRetries: 3,
    });

    return this.parseGmailMessage(message);
  }

  /**
   * Fetch all messages from specified threads
   *
   * This is MORE EFFICIENT than fetching individual messages because:
   * - Makes 1 API call per thread instead of 1 per message
   * - Automatically includes ALL messages in each thread with current labels
   * - Handles label synchronization for old messages automatically
   *
   * Example: 100 messages in 5 threads = 5 API calls instead of 100
   *
   * @param threadIds - Array of Gmail thread IDs to fetch
   * @param options - Fetch options (format, error handling)
   * @returns Fetch result with ALL messages from ALL threads
   *
   * @example
   * ```typescript
   * // Get thread IDs from messages.list (lightweight)
   * const listResult = await fetcher.fetchEmails({
   *   query: 'after:2024-01-01',
   *   format: 'minimal'
   * });
   * const threadIds = [...new Set(listResult.emails.map(e => e.threadId))];
   *
   * // Fetch complete threads (much fewer API calls!)
   * const allMessages = await fetcher.fetchEmailsByThreads(threadIds);
   * ```
   */
  async fetchEmailsByThreads(
    threadIds: string[],
    options: {
      format?: 'full' | 'metadata' | 'minimal';
      continueOnError?: boolean;
    } = {}
  ): Promise<FetchEmailsResult> {
    const startTime = Date.now();
    const { format = 'full', continueOnError = true } = options;

    logger.info({ threadCount: threadIds.length }, `Fetching ${threadIds.length} threads using thread-based fetching`);

    const allEmails: EmailMessage[] = [];
    const allErrors: FetchError[] = [];

    // Fetch each thread (returns ALL messages in thread)
    for (const threadId of threadIds) {
      try {
        const thread = await this.gmailClient.getThread(threadId, format, {
          retryOnRateLimit: true,
          maxRetries: 3,
        });

        if (!thread.messages || thread.messages.length === 0) {
          console.warn(`Thread ${threadId} has no messages`);
          continue;
        }

        console.debug(`Thread ${threadId}: ${thread.messages.length} messages`);

        // Parse all messages in this thread
        for (const message of thread.messages) {
          try {
            const email = this.parseGmailMessage(message);
            allEmails.push(email);
          } catch (error) {
            const err = error as Error;
            allErrors.push({
              messageId: message.id || 'unknown',
              error: `Failed to parse message: ${err.message}`,
              errorCode: undefined,
              stackTrace: process.env.NODE_ENV === 'development' ? err.stack : undefined,
              timestamp: new Date(),
            });

            if (!continueOnError) {
              throw error;
            }
          }
        }
      } catch (error) {
        const err = error as Error & { code?: string | number };
        allErrors.push({
          messageId: threadId,
          error: `Failed to fetch thread: ${err.message}`,
          errorCode: err.code,
          stackTrace: process.env.NODE_ENV === 'development' ? err.stack : undefined,
          timestamp: new Date(),
        });

        console.error(`Failed to fetch thread ${threadId}:`, err);

        if (!continueOnError) {
          throw error;
        }
      }
    }

    const durationMs = Date.now() - startTime;

    console.log(`Thread-based fetch completed: ${allEmails.length} messages from ${threadIds.length} threads`, {
      duration: `${durationMs}ms`,
      errors: allErrors.length,
    });

    return {
      emails: allEmails,
      totalFetched: allEmails.length,
      hasMore: false, // Thread fetching doesn't use pagination
      nextPageToken: undefined,
      errors: allErrors,
      durationMs,
    };
  }

  /**
   * Fetch message details in batches
   *
   * @param messages - Message references from list API
   * @param format - Message format
   * @param batchSize - Number of messages to fetch concurrently
   * @param continueOnError - Whether to continue on individual errors
   * @param errors - Array to collect errors
   * @returns Fetched email messages
   * @private
   */
  private async fetchMessageDetails(
    messages: gmail_v1.Schema$Message[],
    format: string,
    batchSize: number,
    continueOnError: boolean,
    errors: FetchError[]
  ): Promise<EmailMessage[]> {
    const emails: EmailMessage[] = [];

    // Process in batches to avoid overwhelming the API
    for (let i = 0; i < messages.length; i += batchSize) {
      const batch = messages.slice(i, i + batchSize);
      const batchPromises = batch.map(async (msg) => {
        // Validate message ID
        if (!msg.id) {
          console.error('Message missing ID:', msg);
          errors.push({
            messageId: 'unknown',
            error: 'Message missing ID from Gmail API',
            timestamp: new Date(),
          });
          return null;
        }

        try {
          const message = await this.gmailClient.getMessage(msg.id, format as 'full' | 'minimal' | 'metadata' | 'raw', {
            retryOnRateLimit: true,
            maxRetries: 3,
          });
          return this.parseGmailMessage(message);
        } catch (error) {
          const err = error as Error & { code?: string | number };
          const errorMessage = err.message || 'Unknown error';

          errors.push({
            messageId: msg.id,
            error: errorMessage,
            errorCode: err.code,
            stackTrace: process.env.NODE_ENV === 'development' ? err.stack : undefined,
            timestamp: new Date(),
          });

          console.error(`Failed to fetch message ${msg.id}:`, err);

          if (!continueOnError) {
            throw error;
          }

          return null;
        }
      });

      const batchResults = await Promise.all(batchPromises);
      const validEmails = batchResults.filter((email): email is EmailMessage => email !== null);
      emails.push(...validEmails);
    }

    return emails;
  }

  /**
   * Parse Gmail API message into EmailMessage format
   *
   * @param message - Gmail API message
   * @returns Parsed email message
   * @throws Error if message is missing required id or threadId
   * @private
   */
  private parseGmailMessage(message: gmail_v1.Schema$Message): EmailMessage {
    // Validate required fields
    if (!message.id) {
      throw new Error('Gmail message missing required id field');
    }
    if (!message.threadId) {
      throw new Error('Gmail message missing required threadId field');
    }
    if (!message.payload) {
      throw new Error('Gmail message missing payload field');
    }

    // Extract headers
    const headers = message.payload.headers || [];
    const subject = this.getHeader(headers, 'Subject') || '(No Subject)';
    const from = this.parseEmailAddress(this.getHeader(headers, 'From'));
    const to = this.parseEmailAddressList(this.getHeader(headers, 'To')) || [];

    if (!from) {
      throw new Error('Gmail message missing valid From header');
    }

    // Parse date
    const dateHeader = this.getHeader(headers, 'Date');
    let date = new Date();
    if (dateHeader) {
      try {
        const parsedDate = new Date(dateHeader);
        // Validate that the date is valid
        if (!isNaN(parsedDate.getTime())) {
          date = parsedDate;
        } else {
          console.warn(`Invalid date header: ${dateHeader}, using current date`);
        }
      } catch (error) {
        console.error(`Date parsing error for: ${dateHeader}, using current date`, error);
      }
    }

    // Transform Gmail API payload to classification-engine format
    const payload = this.transformPayload(message.payload);

    // Build EmailMessage
    const email: EmailMessage = {
      id: message.id,
      threadId: message.threadId,
      gmailLabels: message.labelIds || [],
      payload,
      subject,
      from,
      to,
      cc: this.parseEmailAddressList(this.getHeader(headers, 'Cc')),
      bcc: this.parseEmailAddressList(this.getHeader(headers, 'Bcc')),
      date,
      snippet: message.snippet || undefined,
      historyId: message.historyId || undefined,
      sizeEstimate: message.sizeEstimate || undefined,
      isProcessed: false,
      processingPriority: 1,
    };

    // Extract body content
    this.extractBodyContent(message.payload, email);

    return email;
  }

  /**
   * Transform Gmail API payload to classification-engine format
   *
   * @param gmailPayload - Gmail API message part
   * @returns Transformed payload
   * @private
   */
  private transformPayload(gmailPayload: gmail_v1.Schema$MessagePart): {
    partId?: string;
    mimeType: string;
    filename?: string;
    headers: EmailHeader[];
    body?: MessagePartBody;
    parts?: MessagePart[];
  } {
    return {
      partId: gmailPayload.partId || undefined,
      mimeType: gmailPayload.mimeType || 'text/plain',
      filename: gmailPayload.filename || undefined,
      headers: (gmailPayload.headers || []).map((h) => ({
        name: h.name || '',
        value: h.value || '',
      })),
      body: gmailPayload.body
        ? {
            attachmentId: gmailPayload.body.attachmentId || undefined,
            size: gmailPayload.body.size || undefined,
            data: gmailPayload.body.data || undefined,
          }
        : undefined,
      parts: gmailPayload.parts ? gmailPayload.parts.map((p) => this.transformPayloadPart(p)) : undefined,
    };
  }

  /**
   * Transform Gmail API message part to classification-engine format
   *
   * @param gmailPart - Gmail API message part
   * @returns Transformed message part
   * @private
   */
  private transformPayloadPart(gmailPart: gmail_v1.Schema$MessagePart): MessagePart {
    return {
      partId: gmailPart.partId || '',
      mimeType: gmailPart.mimeType || 'text/plain',
      filename: gmailPart.filename || undefined,
      headers: (gmailPart.headers || []).map((h) => ({
        name: h.name || '',
        value: h.value || '',
      })),
      body: gmailPart.body
        ? {
            attachmentId: gmailPart.body.attachmentId || undefined,
            size: gmailPart.body.size || undefined,
            data: gmailPart.body.data || undefined,
          }
        : undefined,
      parts: gmailPart.parts ? gmailPart.parts.map((p) => this.transformPayloadPart(p)) : undefined,
    };
  }

  /**
   * Get header value by name
   *
   * @param headers - Email headers
   * @param name - Header name
   * @returns Header value or undefined
   * @private
   */
  private getHeader(headers: gmail_v1.Schema$MessagePartHeader[], name: string): string | undefined {
    const header = headers.find((h) => h.name?.toLowerCase() === name.toLowerCase());
    return header?.value || undefined;
  }

  /**
   * Parse email address from header value using RFC-compliant parser
   *
   * @param headerValue - Header value
   * @returns Parsed email address or undefined
   * @private
   */
  private parseEmailAddress(headerValue?: string): EmailAddress | undefined {
    if (!headerValue) {
      return undefined;
    }

    try {
      const parsed = parseOneAddress(headerValue);
      if (!parsed || parsed.type !== 'mailbox') {
        console.warn(`Invalid email address format: ${headerValue}`);
        return undefined;
      }

      return {
        email: parsed.address,
        name: parsed.name || undefined,
        raw: headerValue,
      };
    } catch (error) {
      console.error(`Email parsing failed for: ${headerValue}`, error);
      return undefined;
    }
  }

  /**
   * Parse comma-separated email address list using RFC-compliant parser
   *
   * @param headerValue - Header value with comma-separated addresses
   * @returns Array of parsed email addresses
   * @private
   */
  private parseEmailAddressList(headerValue?: string): EmailAddress[] | undefined {
    if (!headerValue) {
      return undefined;
    }

    try {
      const parsed = parseAddressList(headerValue);
      if (!parsed) {
        console.warn(`Invalid email address list: ${headerValue}`);
        return undefined;
      }

      const addresses = parsed
        .filter((addr) => addr.type === 'mailbox')
        .map((addr) => ({
          email: addr.address,
          name: addr.name || undefined,
          raw: headerValue,
        }));

      return addresses.length > 0 ? addresses : undefined;
    } catch (error) {
      console.error(`Email list parsing failed for: ${headerValue}`, error);
      return undefined;
    }
  }

  /**
   * Extract body content from message payload with error handling
   *
   * @param part - Message part
   * @param email - Email message to populate
   * @private
   */
  private extractBodyContent(part: gmail_v1.Schema$MessagePart, email: EmailMessage): void {
    // Check if this part has body data
    if (part.body?.data) {
      try {
        const decodedData = Buffer.from(part.body.data, 'base64').toString('utf-8');

        if (part.mimeType === 'text/plain') {
          email.bodyPlain = decodedData;
        } else if (part.mimeType === 'text/html') {
          email.bodyHtml = decodedData;
        }
      } catch (error) {
        console.error(`Failed to decode body for mimeType ${part.mimeType}:`, error);
        // Continue processing other parts
      }
    }

    // Recursively process nested parts
    if (part.parts) {
      for (const subPart of part.parts) {
        this.extractBodyContent(subPart, email);
      }
    }
  }
}

