     1→/**
     2→ * Template Utility Functions
     3→ *
     4→ * Shared utilities for AI prompt template interpolation and formatting.
     5→ * Used by both ai-feature-extraction.ts and ai-classification.ts stages.
     6→ *
     7→ * Key Features:
     8→ * - Secure template interpolation with injection prevention
     9→ * - Email formatting and body extraction
    10→ * - Progressive object formatting (pretty → compact)
    11→ * - Output sanitization for security
    12→ */
    13→
    14→import { EmailMessage } from '../types';
    15→import { logger } from '../utils/logger';
    16→
    17→/**
    18→ * Format email address for prompt display
    19→ *
    20→ * Handles various input formats and returns a consistent display format.
    21→ *
    22→ * @param address - Email address in various formats (string, object, etc.)
    23→ * @returns Formatted email address string
    24→ *
    25→ * @example
    26→ * formatEmailAddress({ name: 'John Doe', email: 'john@example.com' })
    27→ * // Returns: "John Doe <john@example.com>"
    28→ */
    29→export function formatEmailAddress(address: unknown): string {
    30→  if (!address) return 'Unknown';
    31→
    32→  if (typeof address === 'string') return address;
    33→
    34→  if (typeof address === 'object' && address !== null) {
    35→    const addr = address as Record<string, string>;
    36→    if (addr.name && addr.email) {
    37→      return `${addr.name} <${addr.email}>`;
    38→    }
    39→    return addr.email || addr.raw || 'Unknown';
    40→  }
    41→
    42→  return 'Unknown';
    43→}
    44→
    45→/**
    46→ * Extract email body text with HTML fallback
    47→ *
    48→ * Prefers plain text body, falls back to HTML with safe stripping of tags,
    49→ * scripts, styles, and entities.
    50→ *
    51→ * @param email - EmailMessage object containing body content
    52→ * @returns Clean text representation of email body
    53→ *
    54→ * @example
    55→ * getEmailBodyText(email)
    56→ * // Returns: "Your monthly statement is now available..."
    57→ */
    58→export function getEmailBodyText(email: EmailMessage): string {
    59→  if (email.bodyPlain) {
    60→    return email.bodyPlain;
    61→  }
    62→
    63→  if (email.bodyHtml) {
    64→    // Improved HTML stripping with better performance and safety
    65→    return email.bodyHtml
    66→      .replace(/<script[^>]*>.*?<\/script>/gi, '') // Remove script blocks
    67→      .replace(/<style[^>]*>.*?<\/style>/gi, '') // Remove style blocks
    68→      .replace(/<[^>]*>/g, '') // Remove HTML tags
    69→      .replace(/&[#A-Za-z0-9]+;/g, ' ') // Remove HTML entities
    70→      .replace(/\s+/g, ' ') // Normalize whitespace
    71→      .trim();
    72→  }
    73→
    74→  return '[No body content available]';
    75→}
    76→
    77→// Template object size limits (in characters)
    78→const TEMPLATE_SIZE_LIMITS = {
    79→  PRETTY_PRINT_LIMIT: 10000, // Use pretty printing below this size
    80→  COMPACT_FORMAT_LIMIT: 15000, // Use compact format below this size
    81→  MAX_TEMPLATE_SIZE: 20000, // Truncate above this size
    82→} as const;
    83→
    84→/**
    85→ * Check if an object contains null/empty values that would benefit from compaction
    86→ * Includes depth limits to prevent excessive recursion
    87→ */
    88→function hasCompactableContent(obj: Record<string, unknown>, maxDepth = 10): boolean {
    89→  if (maxDepth <= 0) return false; // Prevent deep recursion
    90→
    91→  for (const value of Object.values(obj)) {
    92→    if (value === null || value === undefined) return true;
    93→    if (Array.isArray(value) && value.length === 0) return true;
    94→    if (typeof value === 'object' && value !== null) {
    95→      const objValue = value as Record<string, unknown>;
    96→      if (Object.keys(objValue).length === 0) return true;
    97→      if (hasCompactableContent(objValue, maxDepth - 1)) return true;
    98→    }
    99→  }
   100→  return false;
   101→}
   102→
   103→/**
   104→ * Recursively compact a single value with circular reference detection and depth limits
   105→ */
   106→function compactValue(value: unknown, seen = new WeakSet<object>(), depth = 0): unknown {
   107→  const MAX_DEPTH = 10; // Much more conservative depth limit
   108→
   109→  if (depth > MAX_DEPTH) {
   110→    logger.warn({ depth, MAX_DEPTH }, 'Object nesting too deep, stopping compaction');
   111→    return undefined; // Remove deeply nested content to prevent issues
   112→  }
   113→
   114→  if (value === null || value === undefined) {
   115→    return undefined;
   116→  }
   117→
   118→  if (Array.isArray(value)) {
   119→    if (seen.has(value)) {
   120→      return '[Circular Reference]'; // Prevent infinite loops
   121→    }
   122→    seen.add(value);
   123→
   124→    const compactedArray = value
   125→      .map((item) => compactValue(item, seen, depth + 1))
   126→      .filter((item) => item !== undefined);
   127→
   128→    seen.delete(value); // Clean up for other branches
   129→    return compactedArray.length > 0 ? compactedArray : undefined;
   130→  }
   131→
   132→  if (typeof value === 'object' && value !== null) {
   133→    if (seen.has(value)) {
   134→      return '[Circular Reference]'; // Prevent infinite loops
   135→    }
   136→    seen.add(value);
   137→
   138→    const compactedObj: Record<string, unknown> = {};
   139→    let hasValidProperties = false;
   140→
   141→    for (const [key, val] of Object.entries(value)) {
   142→      const compactedVal = compactValue(val, seen, depth + 1);
   143→      if (compactedVal !== undefined) {
   144→        compactedObj[key] = compactedVal;
   145→        hasValidProperties = true;
   146→      }
   147→    }
   148→
   149→    seen.delete(value); // Clean up for other branches
   150→    return hasValidProperties ? compactedObj : undefined;
   151→  }
   152→
   153→  return value;
   154→}
   155→
   156→/**
   157→ * Create a deeply compacted version of an object by removing nulls, empties recursively
   158→ * with protection against circular references and stack overflow
   159→ */
   160→function createCompactedObject(obj: Record<string, unknown>): Record<string, unknown> {
   161→  const seen = new WeakSet<object>();
   162→  const result = compactValue(obj, seen, 0);
   163→  return (result as Record<string, unknown>) || {};
   164→}
   165→
   166→/**
   167→ * Format an object for template inclusion with progressive compaction
   168→ *
   169→ * Progressive approach:
   170→ * 1. Check if compaction would be beneficial (has nulls/empties)
   171→ * 2. If beneficial, apply compaction first
   172→ * 3. Choose format based on size: pretty -> compact -> minified -> truncated
   173→ * Optimized to minimize JSON.stringify() calls for better performance
   174→ *
   175→ * @param obj - Object to format for template inclusion
   176→ * @returns JSON string representation (pretty or compact)
   177→ *
   178→ * @example
   179→ * formatObjectForTemplate({ category: 'financial', score: 8.5 })
   180→ * // Returns: "{\n  \"category\": \"financial\",\n  \"score\": 8.5\n}"
   181→ */
   182→export function formatObjectForTemplate(obj: Record<string, unknown>): string {
   183→  const startTime = Date.now();
   184→  let originalSize: number | undefined;
   185→
   186→  try {
   187→    // Step 1: Determine if we should compact (has null/empty values)
   188→    const shouldCompact = hasCompactableContent(obj);
   189→    const objectToFormat = shouldCompact ? createCompactedObject(obj) : obj;
   190→
   191→    // Step 2: Calculate compact JSON first (smallest computation)
   192→    const compactJson = JSON.stringify(objectToFormat);
   193→
   194→    // Add memory usage warning for large objects
   195→    if (compactJson.length > 100000) {
   196→      // 100KB threshold
   197→      logger.warn({ size: compactJson.length }, 'Large object detected - consider processing in smaller chunks');
   198→    }
   199→
   200→    // Step 3: Choose format based on compact size (avoiding additional stringify calls)
   201→    if (compactJson.length <= TEMPLATE_SIZE_LIMITS.PRETTY_PRINT_LIMIT) {
   202→      // Only calculate pretty JSON if compact format would fit in pretty limit
   203→      const prettyJson = JSON.stringify(objectToFormat, null, 2);
   204→      return prettyJson;
   205→    }
   206→
   207→    if (compactJson.length <= TEMPLATE_SIZE_LIMITS.COMPACT_FORMAT_LIMIT) {
   208→      return compactJson;
