/**
 * Attribute Detection Stage
 *
 * Stage 4 of the EmailCategorizer pipeline. Detects and derives contextual attributes
 * from email content and metadata that will influence category scoring in the next stage.
 *
 * Implements pattern-based and derived attribute detection per SCORING_LOGIC.md
 * "Attribute Detectors & Derived Attributes" section.
 */

import { EmailMessage, AttributeDetector, DerivedAttribute } from '../types';
import { logger } from '../utils/logger';
import { ClassificationSession } from '../types/classification-session';
import { ClassificationResult } from '../types/classification-result';
import { extractEmailBodyText } from '../utils/email-utils';

/**
 * Individual detected attribute result
 */
export interface DetectedAttribute {
  attributeName: string;
  attributeValue: boolean | string | number;
  detectionMethod: 'pattern' | 'derived' | 'domainLookup';
  detectionEvidence: string;
  confidence: number;
}

/**
 * Result of attribute detection stage
 */
export interface AttributeDetectionResult {
  detectedAttributes: DetectedAttribute[];
  processingDurationMs: number;
  parallelProcessed: boolean;
  dependencies: string[];
  // Preserve previous stage data
  [key: string]: unknown;
}

/**
 * Attribute Detection Stage Configuration
 */
export interface AttributeDetectionStageConfig {
  settings: {
    attributeProcessing: {
      detectSelfSent: boolean;
      resolveDomains: boolean;
      deriveContextFlags: boolean;
    };
  };
  attributes: {
    schema: Record<string, unknown>;
    detectors: AttributeDetector[];
    derived: Record<string, DerivedAttribute>;
    attributeBonusMap?: Record<string, Record<string, number>>;
  };
  performanceCache?: {
    financialDomains?: string[];
    newsletterDomains?: string[];
    logisticsDomains?: string[];
  };
}

/**
 * Execute attribute detection stage function (canonical signature)
 *
 * Mutates the result object in place by populating attributeContext.detectedAttributes
 * and updating session performance metrics.
 */
export function executeAttributeDetection(
  email: EmailMessage,
  session: ClassificationSession,
  result: ClassificationResult,
  config: AttributeDetectionStageConfig
): void {
  const startTime = Date.now();

  const detectedAttributes: DetectedAttribute[] = [];

  // Apply pattern-based detectors
  const patternAttributes = detectPatternAttributes(email, config);
  detectedAttributes.push(...patternAttributes);

  // Apply derived attribute logic
  const derivedAttributes = detectDerivedAttributes(email, config);
  detectedAttributes.push(...derivedAttributes);

  // Detect urgency level and update result
  const urgencyLevel = detectUrgency(email);
  if (urgencyLevel !== 'none') {
    // Only update if different from default 'none'
    result.attributeContext.urgency = urgencyLevel;
  }

  // Mutate result: Update attribute context with detected attributes
  for (const attr of detectedAttributes) {
    result.attributeContext.detectionMetadata[attr.attributeName] = {
      confidence: attr.confidence,
      detectionMethod: attr.detectionMethod,
      evidence: attr.detectionEvidence,
      detectedAt: new Date(),
    };
  }

  // Track performance in session
  const duration = Date.now() - startTime;
  if (!session.performanceMetrics) {
    session.performanceMetrics = {
      totalDurationMs: 0,
      avgEmailDurationMs: 0,
      parallelStagesCount: 0,
      databaseBatchOps: 0,
    };
  }
  session.performanceMetrics.parallelStagesCount += 1;

  // Update result processing duration
  result.processingDurationMs += duration;

  // Add parallel stage result tracking
  result.parallelStageResults.push({
    stageId: `attribute_detection_${result.id}`,
    stageName: 'attributeDetection',
    executionTimeMs: duration,
    parallelWithStages: [], // This stage can run in parallel
    dependentOnStages: ['ruleScoring'], // Depends on earlier stages
    cacheHitsCount: 0,
    errorCount: 0,
  });

  // Update explainability trace (convert to ExplainabilityTrace.AttributeDetectionResult format)
  result.explainabilityTrace.attributeDetection = detectedAttributes.map((attr) => ({
    attribute: attr.attributeName,
    detected: true,
    detectionMethod:
      attr.detectionMethod === 'pattern' || attr.detectionMethod === 'domainLookup' ? 'direct' : 'derived',
    sourceField: attr.detectionMethod === 'pattern' ? 'emailBodyOrSubject' : undefined,
    derivationLogic:
      attr.detectionMethod === 'derived' || attr.detectionMethod === 'domainLookup'
        ? attr.detectionEvidence
        : undefined,
    confidence: attr.confidence,
    parallelProcessed: true,
    dependencies: [],
    reason: attr.detectionEvidence,
  }));

  result.explainabilityTrace.stageTimings['attributeDetection'] = duration;
  result.explainabilityTrace.configurationRefs['attributeDetection'] = 'attributes.detectors';
}

/**
 * Detect pattern-based attributes using configured detectors
 */
function detectPatternAttributes(email: EmailMessage, config: AttributeDetectionStageConfig): DetectedAttribute[] {
  const detectors = config.attributes?.detectors || [];
  const detectedAttributes: DetectedAttribute[] = [];

  for (const detector of detectors) {
    try {
      const detection = applyDetector(email, detector);
      if (detection.detected) {
        detectedAttributes.push({
          attributeName: detector.attribute,
          attributeValue: detection.value as string | number | boolean,
          detectionMethod: 'pattern',
          detectionEvidence: detection.evidence || 'Pattern match',
          confidence: 0.8, // Default confidence for pattern matches
        });
      }
    } catch (error) {
      // Log error but continue processing
      logger.warn({ attribute: detector.attribute, error }, 'Error applying detector');
    }
  }

  return detectedAttributes;
}

/**
 * Apply individual detector pattern to email content
 */
function applyDetector(
  email: EmailMessage,
  detector: AttributeDetector
): { detected: boolean; value?: unknown; evidence?: string } {
  const { field, operation, values } = detector;

  // Get the field content to search
  let searchContent = '';
  switch (field) {
    case 'body':
      searchContent = extractEmailBodyText(email);
      break;
    case 'subject':
      searchContent = email.subject || '';
      break;
    case 'from.address':
      searchContent = email.from?.email || '';
      break;
    case 'from.name':
      searchContent = email.from?.name || '';
      break;
    default:
      logger.warn({ field }, 'Unknown field type for detector');
      return { detected: false };
  }

  // Apply detection operation
  switch (operation) {
    case 'containsAny':
      for (const value of values) {
        if (searchContent.toLowerCase().includes(value.toLowerCase())) {
          return {
            detected: true,
            value: true,
            evidence: `Found "${value}" in ${field}`,
          };
        }
      }
      break;

    case 'regexAny':
      for (const pattern of values) {
        try {
          const regex = new RegExp(pattern, 'ig'); // Add global flag for better matching
          const match = searchContent.match(regex);
          if (match) {
            // For amount patterns, try to match the longest currency pattern
            let bestMatch = match[0];
            if (pattern.includes('\\$\\d+')) {
              // Special handling for currency amounts - match full amounts with decimals
              const fullAmountRegex = /\$\d+(?:\.\d{2})?/g;
              const fullMatches = searchContent.match(fullAmountRegex);
              if (fullMatches && fullMatches.length > 0) {
                bestMatch = fullMatches[0]; // Use the first full amount match
              }
            }
            return {
              detected: true,
              value: true,
              evidence: `Regex "${pattern}" matched: "${bestMatch}" in ${field}`,
            };
          }
        } catch (error) {
          logger.warn({ pattern, error }, 'Invalid regex pattern');
          continue;
        }
      }
      break;

    case 'startsWith':
      for (const value of values) {
        if (searchContent.toLowerCase().startsWith(value.toLowerCase())) {
          return {
            detected: true,
            value: true,
            evidence: `${field} starts with "${value}"`,
          };
        }
      }
      break;

    case 'endsWith':
      for (const value of values) {
        if (searchContent.toLowerCase().endsWith(value.toLowerCase())) {
          return {
            detected: true,
            value: true,
            evidence: `${field} ends with "${value}"`,
          };
        }
      }
      break;

    default:
      logger.warn({ operation }, 'Unknown operation type');
  }

  return { detected: false };
}

/**
 * Detect derived attributes using logical rules
 */
function detectDerivedAttributes(email: EmailMessage, config: AttributeDetectionStageConfig): DetectedAttribute[] {
  const settings = config.settings?.attributeProcessing;
  const detectedAttributes: DetectedAttribute[] = [];

  // Derive selfSent attribute (if enabled, default true)
  const detectSelfSent = !settings || settings.detectSelfSent !== false;
  if (detectSelfSent) {
    const selfSent = deriveSelfSent(email);
    if (selfSent) {
      detectedAttributes.push(selfSent);
    }
  }

  // Domain-based derivations (if enabled, default true)
  const resolveDomains = !settings || settings.resolveDomains !== false;
  if (resolveDomains) {
    // Derive fromFinancialInstitution attribute
    const financialInstitution = deriveFromFinancialInstitution(email, config);
    if (financialInstitution) {
      detectedAttributes.push(financialInstitution);
    }

    // Derive fromNewsletterSource attribute
    const newsletterSource = deriveFromNewsletterSource(email, config);
    if (newsletterSource) {
      detectedAttributes.push(newsletterSource);
    }

    // Derive fromLogisticsCarrier attribute
    const logisticsCarrier = deriveFromLogisticsCarrier(email, config);
    if (logisticsCarrier) {
      detectedAttributes.push(logisticsCarrier);
    }
  }

  // Gmail category derivations (always enabled - based on Gmail API labelIds)
  const gmailCategories = deriveGmailCategories(email);
  detectedAttributes.push(...gmailCategories);

  return detectedAttributes;
}

/**
 * Derive selfSent attribute - email sent from user to self
 */
function deriveSelfSent(email: EmailMessage): DetectedAttribute | null {
  const userAddresses = getUserAddresses();
  const fromAddress = email.from?.email?.toLowerCase();

  // Check if from address is user address
  if (!fromAddress || !userAddresses.includes(fromAddress)) {
    return null;
  }

  // Check if all recipients are user addresses
  const allRecipients: string[] = [];
  if (email.to) {
    allRecipients.push(...email.to.map((addr) => addr.email.toLowerCase()));
  }
  if (email.cc) {
    allRecipients.push(...email.cc.map((addr) => addr.email.toLowerCase()));
  }
  if (email.bcc) {
    allRecipients.push(...email.bcc.map((addr) => addr.email.toLowerCase()));
  }

  const allRecipientsAreUser = allRecipients.length > 0 && allRecipients.every((addr) => userAddresses.includes(addr));

  // Check for List-Id header (exclude mailing lists)
  const hasListId = email.payload?.headers?.some((header) => header.name.toLowerCase() === 'list-id');

  if (allRecipientsAreUser && !hasListId) {
    return {
      attributeName: 'selfSent',
      attributeValue: true,
      detectionMethod: 'derived',
      detectionEvidence: 'All recipients match user addresses',
      confidence: 0.9,
    };
  }

  return null;
}

/**
 * Derive fromFinancialInstitution attribute using domain lookup
 */
function deriveFromFinancialInstitution(
  email: EmailMessage,
  config: AttributeDetectionStageConfig
): DetectedAttribute | null {
  const fromAddress = email.from?.email?.toLowerCase();
  if (!fromAddress) return null;

  const fromDomain = extractBaseDomain(fromAddress);
  const financialDomains = getFinancialDomains(config);

  if (financialDomains.includes(fromDomain)) {
    return {
      attributeName: 'fromFinancialInstitution',
      attributeValue: true,
      detectionMethod: 'domainLookup',
      detectionEvidence: fromDomain,
      confidence: 0.85,
    };
  }

  return null;
}

/**
 * Derive fromNewsletterSource attribute
 */
function deriveFromNewsletterSource(
  email: EmailMessage,
  config: AttributeDetectionStageConfig
): DetectedAttribute | null {
  const fromAddress = email.from?.email?.toLowerCase();
  if (!fromAddress) return null;

  const fromDomain = extractBaseDomain(fromAddress);
  const newsletterDomains = getNewsletterDomains(config);

  // Check domain match
  if (newsletterDomains.includes(fromDomain)) {
    return {
      attributeName: 'fromNewsletterSource',
      attributeValue: true,
      detectionMethod: 'domainLookup',
      detectionEvidence: fromDomain,
      confidence: 0.8,
    };
  }

  // Check List-Id header presence
  const hasListId = email.payload?.headers?.some((header) => header.name.toLowerCase() === 'list-id');
  if (hasListId) {
    return {
      attributeName: 'fromNewsletterSource',
      attributeValue: true,
      detectionMethod: 'derived',
      detectionEvidence: 'List-Id header present',
      confidence: 0.85,
    };
  }

  return null;
}

/**
 * Derive fromLogisticsCarrier attribute
 */
function deriveFromLogisticsCarrier(
  email: EmailMessage,
  config: AttributeDetectionStageConfig
): DetectedAttribute | null {
  const fromAddress = email.from?.email?.toLowerCase();
  if (!fromAddress) return null;

  const fromDomain = extractBaseDomain(fromAddress);
  const logisticsDomains = getLogisticsDomains(config);

  if (logisticsDomains.includes(fromDomain)) {
    return {
      attributeName: 'fromLogisticsCarrier',
      attributeValue: true,
      detectionMethod: 'domainLookup',
      detectionEvidence: fromDomain,
      confidence: 0.85,
    };
  }

  return null;
}

/**
 * Extract base domain from email address
 */
function extractBaseDomain(email: string): string {
  const domainPart = email.split('@')[1];
  if (!domainPart) return '';

  // Handle subdomains - return main domain for common patterns
  const parts = domainPart.split('.');
  if (parts.length >= 2) {
    return parts.slice(-2).join('.');
  }
  return domainPart;
}

/**
 * Get user email addresses for selfSent detection
 */
function getUserAddresses(): string[] {
  // In real implementation, this would come from user configuration
  return ['user@gmail.com', 'scotthamilton77@gmail.com'];
}

/**
 * Get financial domains for institution detection
 */
function getFinancialDomains(config: AttributeDetectionStageConfig): string[] {
  return config.performanceCache?.financialDomains || [];
}

/**
 * Get newsletter domains for source detection
 */
function getNewsletterDomains(config: AttributeDetectionStageConfig): string[] {
  return config.performanceCache?.newsletterDomains || [];
}

/**
 * Get logistics domains for carrier detection
 */
function getLogisticsDomains(config: AttributeDetectionStageConfig): string[] {
  return config.performanceCache?.logisticsDomains || [];
}

/**
 * Derive Gmail category attributes from Gmail API labelIds
 *
 * Gmail automatically categorizes emails into Social, Promotions, and Updates.
 * These categories are exposed via Gmail API as labelIds: CATEGORY_SOCIAL,
 * CATEGORY_PROMOTIONS, CATEGORY_UPDATES.
 *
 * We use these as PRIMARY_BOOST signals to boost relevant categories:
 * - CATEGORY_SOCIAL → boosts personal category
 * - CATEGORY_PROMOTIONS → boosts marketingPromotions category
 * - CATEGORY_UPDATES → boosts subscriptionContent/systemNotifications categories
 *
 * TODO this should be configuration-driven
 */
function deriveGmailCategories(email: EmailMessage): DetectedAttribute[] {
  const gmailLabels = email.gmailLabels || [];
  const detectedAttributes: DetectedAttribute[] = [];

  // Check for Social category
  if (gmailLabels.includes('CATEGORY_SOCIAL')) {
    detectedAttributes.push({
      attributeName: 'gmailCategorySocial',
      attributeValue: true,
      detectionMethod: 'derived',
      detectionEvidence: 'Gmail labeled as CATEGORY_SOCIAL',
      confidence: 0.9, // High confidence - Gmail's ML is sophisticated
    });
  }

  // Check for Promotions category
  if (gmailLabels.includes('CATEGORY_PROMOTIONS')) {
    detectedAttributes.push({
      attributeName: 'gmailCategoryPromotions',
      attributeValue: true,
      detectionMethod: 'derived',
      detectionEvidence: 'Gmail labeled as CATEGORY_PROMOTIONS',
      confidence: 0.9,
    });
  }

  // Check for Updates category
  if (gmailLabels.includes('CATEGORY_UPDATES')) {
    detectedAttributes.push({
      attributeName: 'gmailCategoryUpdates',
      attributeValue: true,
      detectionMethod: 'derived',
      detectionEvidence: 'Gmail labeled as CATEGORY_UPDATES',
      confidence: 0.9,
    });
  }

  return detectedAttributes;
}

/**
 * Detect urgency level from email content and headers
 *
 * Analyzes subject, body, and X-Priority header to determine urgency level.
 * Returns one of: 'none', 'low', 'medium', 'high' (matching config schema)
 *
 * TODO: Make this configuration-driven rather than hardcoded
 * Suggested approach: Add urgency detectors to config.processingConfig.attributes.detectors
 * with tier-based patterns similar to rule-based classification:
 * {
 *   "attribute": "urgency",
 *   "tiers": {
 *     "high": { patterns: [...], headerConditions: { "X-Priority": [1, 2] } },
 *     "medium": { patterns: [...], headerConditions: { "X-Priority": [3] } },
 *     "low": { patterns: [...] },
 *     "none": { isDefault: true }
 *   }
 * }
 *
 * Current hardcoded patterns:
 *
 * High urgency indicators:
 * - Keywords: "urgent", "immediately", "asap", "critical", "emergency", "overdue", "action required"
 * - X-Priority header: 1 or 2
 *
 * Medium urgency indicators:
 * - Keywords: "soon", "important", "please review", "time sensitive"
 * - X-Priority header: 3
 *
 * Low urgency indicators:
 * - Keywords: "fyi", "no rush", "when you have time", "at your convenience"
 * - X-Priority header: 4 or 5
 *
 * None urgency: No urgency indicators detected (current default)
 */
function detectUrgency(email: EmailMessage): 'none' | 'low' | 'medium' | 'high' {
  const subject = (email.subject || '').toLowerCase();
  const body = extractEmailBodyText(email).toLowerCase();
  const contentText = `${subject} ${body}`;

  // Check X-Priority header (1 = highest, 5 = lowest)
  const xPriority = email.payload?.headers?.find((h) => h.name.toLowerCase() === 'x-priority')?.value;
  const priorityNum = xPriority ? parseInt(xPriority, 10) : null;

  // High urgency patterns
  const highUrgencyKeywords = [
    'urgent',
    'immediately',
    'asap',
    'critical',
    'emergency',
    'overdue',
    'action required',
    'respond immediately',
    'time-sensitive',
  ];

  // Medium urgency patterns
  const mediumUrgencyKeywords = [
    'soon',
    'important',
    'please review',
    'time sensitive',
    'attention needed',
    'follow up',
  ];

  // Low urgency patterns
  const lowUrgencyKeywords = ['fyi', 'for your information', 'no rush', 'when you have time', 'at your convenience'];

  // Check for high urgency
  if (priorityNum !== null && priorityNum <= 2) {
    return 'high';
  }

  for (const keyword of highUrgencyKeywords) {
    if (contentText.includes(keyword)) {
      return 'high';
    }
  }

  // Check for medium urgency
  if (priorityNum === 3) {
    return 'medium';
  }

  for (const keyword of mediumUrgencyKeywords) {
    if (contentText.includes(keyword)) {
      return 'medium';
    }
  }

  // Check for explicit low urgency (X-Priority 4 or 5)
  if (priorityNum !== null && priorityNum >= 4) {
    return 'low';
  }

  // Check for low urgency keywords
  for (const keyword of lowUrgencyKeywords) {
    if (contentText.includes(keyword)) {
      return 'low';
    }
  }

  // Default to 'none' (no urgency indicators detected)
  // This matches config schema which includes "none" as a valid value
  return 'none';
}

