     1→/**
     2→ * AI Feature Extraction Stage
     3→ *
     4→ * Stage 8a of the EmailCategorizer pipeline. Uses LangChain OpenAI integration with GPT-4o-mini
     5→ * for semantic feature extraction with JSON schema validation and batch processing support.
     6→ *
     7→ * This stage is responsible for:
     8→ * - Calling OpenAI API with structured prompts and email content
     9→ * - Validating AI responses against JSON schema
    10→ * - Extracting semantic intent and category enhancements
    11→ * - Validating evidence grounding (quoted phrases must exist in email)
    12→ * - Providing retry logic and error handling for API failures
    13→ * - Supporting batch processing with concurrent API calls
    14→ */
    15→
    16→import Ajv from 'ajv';
    17→import { logger } from '../utils/logger';
    18→import { OpenAI } from 'openai';
    19→import { ClassificationSession, EmailMessage } from '../types';
    20→import { ClassificationResult, CandidateScore } from '../types/classification-result';
    21→import { AttributeContext } from '../types/attribute-context';
    22→import {
    23→  formatEmailAddress,
    24→  formatObjectForTemplate,
    25→  getEmailBodyText,
    26→  interpolateTemplate,
    27→} from '../utils/template-utils';
    28→
    29→// Configuration interface for AI feature extraction
    30→export interface AIFeatureExtractionConfig {
    31→  openai: {
    32→    apiKey: string;
    33→    model: string;
    34→    temperature: number;
    35→    responseFormat: 'json_schema' | 'json_object'; // Support both for backward compatibility
    36→  };
    37→  prompts: {
    38→    systemPrompt: string[];
    39→    userPrompt: string[];
    40→  };
    41→  featureExtractionSchema: {
    42→    name?: string;
    43→    description?: string;
    44→    schema: Record<string, unknown>;
    45→    strict?: boolean;
    46→  };
    47→  retryPolicy: {
    48→    maxRetries: number;
    49→    backoffMs: number;
    50→  };
    51→}
    52→
    53→// Semantic intent extracted by AI
    54→export interface SemanticIntent {
    55→  primaryPurpose: 'notification' | 'request' | 'update' | 'alert';
    56→  actionRequired: 'none' | 'view' | 'respond' | 'complete';
    57→  urgencyLevel: 'none' | 'low' | 'medium' | 'high';
    58→}
    59→
    60→// Evidence structure for category enhancements
    61→export interface CategoryEvidence {
    62→  quotedPhrases: string[];
    63→  keywords: string[];
    64→  reasoning: string;
    65→}
    66→
    67→// Category enhancement from AI analysis
    68→export interface CategoryEnhancement {
    69→  applies: boolean;
    70→  confidenceBoost: number;
    71→  evidence: CategoryEvidence;
    72→}
    73→
    74→// Complete feature extraction result from AI
    75→export interface FeatureExtractionData {
    76→  semanticIntent: SemanticIntent;
    77→  categoryEnhancements: Record<string, CategoryEnhancement>;
    78→}
    79→
    80→// Evidence validation result
    81→export interface EvidenceValidation {
    82→  validPhrases: string[];
    83→  invalidPhrases: string[];
    84→  fabricationDetected: boolean;
    85→}
    86→
    87→// Complete stage result interface
    88→export interface FeatureExtractionResult {
    89→  featureExtraction: FeatureExtractionData;
    90→  validationPassed: boolean;
    91→  validationErrors: string[];
    92→  evidenceValidation: EvidenceValidation;
    93→  processingDurationMs: number;
    94→  tokenUsage: number;
    95→  apiCallCount: number;
    96→  retryCount: number;
    97→}
    98→
    99→/**
   100→ * AI Feature Extraction Stage Implementation
   101→ *
   102→ * Integrates with OpenAI GPT-4o-mini to extract semantic features and enhance
   103→ * category classifications with evidence-grounded analysis.
   104→ *
   105→ * CANONICAL SIGNATURE: (email, session, result, config) => Promise<void>
   106→ * Mutates result object by storing feature extraction data in explainabilityTrace
   107→ */
   108→export async function aiFeatureExtractionStage(
   109→  email: EmailMessage,
   110→  session: ClassificationSession,
   111→  result: ClassificationResult,
   112→  config: AIFeatureExtractionConfig
   113→): Promise<void> {
   114→  const startTime = Date.now();
   115→  let retryCount = 0;
   116→  let apiCallCount = 0;
   117→
   118→  // Validate inputs
   119→  validateInputs(email, session, result, config);
   120→
   121→  // Extract candidate categories and detected attributes from result
   122→  const candidateCategories = result.candidateScores;
   123→  const detectedAttributes = result.attributeContext;
   124→
   125→  // Initialize OpenAI client
   126→  const openai = new OpenAI({
   127→    apiKey: config.openai.apiKey,
   128→  });
   129→
   130→  // Setup JSON schema validator (only used for legacy json_object mode)
   131→  const ajv = new Ajv();
   132→  const validateSchema = ajv.compile(config.featureExtractionSchema.schema);
   133→
   134→  // Retry loop for API calls
   135→  let lastError: Error | null = null;
   136→
   137→  while (retryCount < config.retryPolicy.maxRetries) {
   138→    try {
   139→      apiCallCount++;
   140→
   141→      // Prepare prompts with email content interpolation
