  'hard-assertions',
  'strong-indicators',
  'rule-scoring',
  'attribute-detection',
  'attribute-influence',
  'disambiguation',
  'multi-label-selection',
  'ai-routing',
  'ai-feature-extraction',
  'ai-classification',
