import { promises as fs, watch, FSWatcher } from 'fs';
import { join, dirname, basename } from 'path';
import { logger } from '../utils/logger';
import { EventEmitter } from 'events';
import { createHash } from 'crypto';
import {
  CategoryConfiguration,
  validateCategoryConfiguration,
  getValidationErrors,
  AttributeRole,
} from './category-config-schema';
import {
  ProcessingConfigTuning,
  validateProcessingConfigTuning,
  getProcessingConfigErrors,
} from './processing-config-schema';

/**
 * Configuration loader with hot-reload capability
 * Monitors configuration files for changes and validates them automatically
 */

export interface ConfigLoadOptions {
  configDir?: string;
  enableHotReload?: boolean;
  validateOnLoad?: boolean;
  compileRules?: boolean;
  cacheTtlMs?: number;
  backupOnChange?: boolean;
}

export interface ConfigLoadResult<T> {
  config: T;
  hash: string;
  lastModified: Date;
  validationPassed: boolean;
  validationErrors: string[];
  loadTime: number;
}

export interface CompiledRule {
  category: string;
  subtype: string;
  tier: 'high' | 'medium' | 'low';
  pattern: RegExp;
  weight: number;
  parallelSafe: boolean;
}

export interface AttributeInfluenceMatrix {
  [category: string]: {
    [attribute: string]: {
      role: AttributeRole;
      bonus: number;
      cap: number;
    };
  };
}

// eslint-disable-next-line @typescript-eslint/no-unsafe-declaration-merging
export class ConfigurationLoader extends EventEmitter {
  private configDir: string;
  private enableHotReload: boolean;
  private validateOnLoad: boolean;
  private compileRules: boolean;
  private cacheTtlMs: number;
  private backupOnChange: boolean;

  private watchers: Map<string, FSWatcher> = new Map();
  private configCache: Map<string, ConfigLoadResult<unknown>> = new Map();
  private lastHashes: Map<string, string> = new Map();

  constructor(options: ConfigLoadOptions = {}) {
    super();

    this.configDir = options.configDir || join(process.cwd(), 'config');
    this.enableHotReload = options.enableHotReload ?? true;
    this.validateOnLoad = options.validateOnLoad ?? true;
    this.compileRules = options.compileRules ?? true;
    this.cacheTtlMs = options.cacheTtlMs ?? 60000; // 1 minute default
    this.backupOnChange = options.backupOnChange ?? true;

    // Clean up watchers on process exit
    process.on('exit', () => this.cleanup());
    process.on('SIGINT', () => this.cleanup());
    process.on('SIGTERM', () => this.cleanup());
  }

  /**
   * Load category configuration with validation and hot-reload setup
   */
  async loadCategoryConfiguration(
    filename: string = 'email-categorizer-config.json'
  ): Promise<ConfigLoadResult<CategoryConfiguration>> {
    const filepath = join(this.configDir, filename);

    try {
      const startTime = Date.now();

      // Check cache first
      const cached = this.getCachedConfig<CategoryConfiguration>(filepath);
      if (cached) {
        return cached;
      }

      // Load and parse configuration
      const fileContent = await fs.readFile(filepath, 'utf-8');
      const hash = this.calculateHash(fileContent);
      const stats = await fs.stat(filepath);

      let config: unknown;
      try {
        config = JSON.parse(fileContent);
      } catch (parseError) {
        throw new Error(
          `Failed to parse JSON in ${filepath}: ${parseError instanceof Error ? parseError.message : String(parseError)}`
        );
      }

      // Validate configuration
      let validationPassed = true;
      let validationErrors: string[] = [];
      let validatedConfig: CategoryConfiguration;

      if (this.validateOnLoad) {
        try {
          validatedConfig = validateCategoryConfiguration(config);

          // Additional custom validation
          validationErrors = await this.validateCategoryConfigurationCustom(validatedConfig);
          validationPassed = validationErrors.length === 0;
        } catch (error) {
          logger.error({ error }, 'Configuration validation failed');
          validationPassed = false;
          validationErrors = getValidationErrors(config);
          validatedConfig = config as CategoryConfiguration; // Use unvalidated config for error reporting
        }
      } else {
        validatedConfig = config as CategoryConfiguration;
      }

      // Compile rules if enabled
      if (this.compileRules && validationPassed) {
        validatedConfig.compiledRules = await this.compileConfigurationRules(validatedConfig);
        validatedConfig.attributeMatrix = await this.computeAttributeMatrix(validatedConfig);
      }

      // Update metadata
      validatedConfig.hash = hash;
      validatedConfig.lastModified = stats.mtime;

/**
 * Gmail Email Fetcher with Pagination
 *
 * Provides robust email fetching capabilities with pagination, batch processing,
 * error recovery, and Gmail API response parsing.
 *
 * ## Page vs Batch Distinction
 *
 * This module uses two levels of chunking for optimal performance:
 *
 * ### Pages (Gmail API Level)
 * - A **page** is a set of message references (IDs) returned by Gmail's `list()` API
 * - Contains only metadata (message ID, thread ID), not full email content
 * - Size controlled by `maxResults` option (default: 100)
 * - Gmail returns `nextPageToken` when more pages are available
 * - Used for **pagination** through large result sets (e.g., 10,000 emails)
 *
 * ### Batches (Implementation Level)
 * - A **batch** is our internal grouping for fetching full message details
 * - After getting a page of IDs, we call `get()` for each to retrieve full content
 * - Instead of fetching all simultaneously, we split into smaller batches
 * - Size controlled by `batchSize` option (default: 10)
 * - Batches are processed **in parallel** using `Promise.all()`
 * - Prevents overwhelming the Gmail API with hundreds of concurrent requests
 *
 * ### Example Flow
 * ```
 * 1. Gmail API list() → Page 1: [msg1...msg100]      (maxResults=100)
 *    ↓
 * 2. Split into batches:
 *    - Batch 1: [msg1...msg10]                       (batchSize=10)
 *    - Batch 2: [msg11...msg20]
 *    - ...
 *    - Batch 10: [msg91...msg100]
 *    ↓
 * 3. Process each batch with Promise.all() for parallel fetching
 *    ↓
 * 4. If nextPageToken exists → fetch Page 2 and repeat
 * ```
 *
 * This two-level approach balances Gmail API limits, network efficiency,
 * and rate limiting while maintaining optimal performance.
 *
 * @packageDocumentation
 */

import { gmail_v1 } from 'googleapis';
import { parseOneAddress, parseAddressList } from 'email-addresses';
import { GmailClient } from './gmail-client';
import {
  EmailMessage,
  EmailHeader,
  EmailAddress,
  MessagePart,
  MessagePartBody,
} from '@gmail-automation/classification-engine';
import { createLogger } from '../logging/logger-factory';

const logger = createLogger();

// Re-export types for convenience
export type { EmailMessage, EmailAddress };

/**
 * Options for fetching emails
 */
export interface FetchEmailsOptions {
  /**
   * Maximum number of emails to fetch per page
   * @default 100
   */
  maxResults?: number;

  /**
   * Gmail search query filter
   */
  query?: string;

  /**
   * Label IDs to filter by
   */
  labelIds?: string[];

  /**
   * Page token for pagination
   */
  pageToken?: string;

  /**
   * Fetch all pages (ignores maxResults for total, but uses it per page)
   * @default false
   */
  fetchAll?: boolean;

  /**
   * Maximum total emails to fetch (safety limit for fetchAll)
   * Prevents memory exhaustion when fetching large mailboxes
   * @default 10000
   */
  maxTotalEmails?: number;

  /**
   * Message format (full, minimal, metadata, raw)
   * @default 'full'
   */
  format?: 'full' | 'minimal' | 'metadata' | 'raw';

  /**
   * Batch size for fetching message details
   * @default 10
   */
  batchSize?: number;

  /**
   * Continue fetching on individual message errors
   * @default true
   */
  continueOnError?: boolean;
}

/**
 * Fetch error details
 */
export interface FetchError {
  /**
   * Message ID that failed
   */
  messageId: string;

  /**
   * Error message
   */
  error: string;

  /**
   * Gmail API error code (if available)
   */
  errorCode?: string | number;

  /**
   * Stack trace for debugging (only in development)
   */
  stackTrace?: string;

  /**
   * Timestamp of error
   */
  timestamp: Date;
}

