/**
 * Hierarchical environment variable loader
 *
 * Loads .env files from current working directory up to filesystem root,
 * with child directories overriding parent directories. This enables
 * standalone usage while maintaining monorepo compatibility.
 *
 * @packageDocumentation
 */

import * as fs from 'fs';
import * as path from 'path';
import { createLogger } from '../logging/logger-factory';

const logger = createLogger();

/**
 * Track loaded environment variables for cleanup
 */
const loadedVars = new Set<string>();

/**
 * Parse .env file content into key-value pairs
 *
 * Supports:
 * - Simple key=value pairs
 * - Quoted values (double and single quotes)
 * - Comments (lines starting with #)
 * - Empty lines
 * - Values containing equals signs
 *
 * @param content - .env file content
 * @returns Map of environment variable key-value pairs
 */
function parseEnvFile(content: string): Map<string, string> {
  const vars = new Map<string, string>();
  const lines = content.split('\n');

  for (const line of lines) {
    const trimmed = line.trim();

    // Skip empty lines and comments
    if (!trimmed || trimmed.startsWith('#')) {
      continue;
    }

    // Find first equals sign
    const equalsIndex = trimmed.indexOf('=');
    if (equalsIndex === -1) {
      continue; // Invalid line, skip
    }

    const key = trimmed.substring(0, equalsIndex).trim();
    let value = trimmed.substring(equalsIndex + 1).trim();

    // Remove surrounding quotes if present
    if ((value.startsWith('"') && value.endsWith('"')) || (value.startsWith("'") && value.endsWith("'"))) {
      value = value.substring(1, value.length - 1);
    }

    if (key) {
      vars.set(key, value);
    }
  }

  return vars;
}

/**
 * Check if we've reached the filesystem root
 *
 * OS-independent detection:
 * - Unix/Linux/Mac: /
 * - Windows: C:\, D:\, etc.
 *
 * @param currentDir - Current directory path
 * @param parentDir - Parent directory path
 * @returns True if at filesystem root
 */
function isFilesystemRoot(currentDir: string, parentDir: string): boolean {
  // Primary check: If parent equals current, we're at root
  // This works for both Unix (/) and Windows (C:\)
  return currentDir === parentDir;
}

/**
 * Walk up directory tree and collect .env file paths
 *
 * @param startDir - Starting directory (usually CWD)
 * @returns Array of .env file paths from root to current (parent first)
 */
function collectEnvFiles(startDir: string): string[] {
  const envFiles: string[] = [];
  let currentDir = startDir;

  while (true) {
    const envPath = path.join(currentDir, '.env');

    // Check if .env exists at this level
    if (fs.existsSync(envPath)) {
      envFiles.unshift(envPath); // Add to beginning (reverse order)
    }

    // Get parent directory
    const parentDir = path.dirname(currentDir);

    // Check if we've reached the filesystem root
    if (isFilesystemRoot(currentDir, parentDir)) {
      break;
    }

    currentDir = parentDir;
  }

  return envFiles;
}

/**
 * Load environment variables from .env files hierarchically
 *
 * Walks up directory tree from starting directory to filesystem root,
 * loading .env files at each level. Child directories override parent
 * directories.
 *
 * Gracefully handles:
 * - Missing .env files (no error)
 * - Permissions errors (stops walking, no error)
 * - File read errors (logs warning, continues)
 *
 * @param startDir - Starting directory (defaults to process.cwd())
 *
 * @example
 * ```typescript
 * // Load from current working directory up to root
 * loadEnvironment();
 *
 * // Load from specific directory
 * loadEnvironment('/app/packages/email-processor');
 * ```
 */
export function loadEnvironment(startDir?: string): void {
  const cwd = startDir || process.cwd();

  try {
    // Collect all .env files from root to current directory
    const envFiles = collectEnvFiles(cwd);

    // Load each file in order (parent → child)
    for (const envFile of envFiles) {
      try {
        const content = fs.readFileSync(envFile, 'utf-8');
        const vars = parseEnvFile(content);

        // Set environment variables (later files override earlier)
        for (const [key, value] of vars) {
          process.env[key] = value;
          loadedVars.add(key);
        }
      } catch (error) {
        // Check for permissions error
        if ((error as NodeJS.ErrnoException).code === 'EACCES') {
          // Permissions error - stop walking up the tree
          break;
        }

        // Other errors - log warning and continue
        logger.warn({ envFile, error }, `Warning: Could not read ${envFile}`);
      }
    }
  } catch (error) {
    // Catch any unexpected errors during directory traversal
    logger.warn({ error }, 'Warning: Error during environment loading');
  }
}

/**
 * Clear all environment variables loaded by loadEnvironment()
 *
 * Useful for testing to reset environment state between tests.
 */
export function clearEnvironment(): void {
  for (const key of loadedVars) {
    delete process.env[key];
  }
  loadedVars.clear();
}

